INSERT INTO gbc_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 5371, 'The Legend of Zelda: Link''s Awakening DX', 'Game Boy Color', 6, 17387, 17387, 17387, 110, 0, 'Action-Adventure', 'Nintendo', 'Nintendo', '1998-12-12', 'The Legend of Zelda: Link''s Awakening DX is a 1998 action-adventure game developed and published by Nintendo for the Game Boy Color. The game is a colorized version of the 1993 Game Boy title The Legend of Zelda: Link''s Awakening, in which protagonist Link must fight monsters, explore dungeons and solve puzzles to escape from Koholint Island. The DX version of Link''s Awakening features gameplay additions including a color-themed dungeon and support for the Game Boy Printer.', 'https://media.retroachievements.org/Images/046977.png', 'https://media.retroachievements.org/Images/005961.png', 'https://media.retroachievements.org/Images/005959.png', 'https://media.retroachievements.org/Images/005960.png', 5),
  (2, 810, 'Pokémon Crystal Version', 'Game Boy Color', 6, 12586, 12586, 12586, 113, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2000-12-14', 'Pokémon Crystal Version is a role-playing video game developed by Game Freak and published by Nintendo for the Game Boy Color, released in Japan in December 2000 and internationally throughout 2001. Serving as an enhanced edition of the 1999 titles Pokémon Gold and Silver, it is the final entry in the second generation of the Pokémon game series. The game introduced several new features, including additional story elements, a Battle Tower area, the option to play as a female protagonist, animated Pokémon sprites during battles, and various minor improvements. The Japanese version of the game also utilized the capabilities of the Mobile Adapter GB, a peripheral that allowed players to trade and battle over cell phones and a paid subscription service called "Mobile System GB". These enhancements were made possible by the Game Boy Color''s improved hardware, making Crystal the first game in the series to be incompatible with the original Game Boy.', 'https://media.retroachievements.org/Images/105173.png', 'https://media.retroachievements.org/Images/024029.png', 'https://media.retroachievements.org/Images/007161.png', 'https://media.retroachievements.org/Images/014324.png', 4.9),
  (3, 4939, 'Tetris DX', 'Game Boy Color', 6, 8775, 8775, 8775, 39, 0, NULL, NULL, 'Nintendo', '1998-10-21', 'Tetris DX is a 1998 video game developed and published by Nintendo for the Game Boy Color. It is a version of the game Tetris and a colorised version of the 1989 port of the game, introducing new gameplay modes, save games, and multiplayer using the Game Link Cable. DX was released as a launch title for the Game Boy Color in October 1998. Upon release, the game received a positive reception, with praise directed towards its gameplay additions. Following release, critics praised the game as one of the best titles for the Game Boy Color.', 'https://media.retroachievements.org/Images/109627.png', 'https://media.retroachievements.org/Images/003691.png', 'https://media.retroachievements.org/Images/003688.png', 'https://media.retroachievements.org/Images/003690.png', 4.9),
  (4, 725, 'Pokémon Pinball', 'Game Boy Color', 6, 7984, 7984, 7984, 78, 0, 'Pinball', 'Jupiter', 'Nintendo', '1999-04-14', 'Pokémon Pinball is a pinball-based Pokémon spin-off video game for the Game Boy Color. It was released in Japan on April 14, 1999, and in North America on June 29, 1999. In it, the ball is a Poké Ball, and most of the objects on the table are Pokémon-related.', 'https://media.retroachievements.org/Images/024809.png', 'https://media.retroachievements.org/Images/005502.png', 'https://media.retroachievements.org/Images/005503.png', 'https://media.retroachievements.org/Images/005501.png', 4.8),
  (5, 676, 'The Legend of Zelda: Oracle of Seasons', 'Game Boy Color', 6, 6826, 6826, 6826, 59, 0, 'Action-Adventure', 'Capcom', 'Nintendo', '2001-02-27', 'The Legend of Zelda: Oracle of Seasons and The Legend of Zelda: Oracle of Ages are 2001 action-adventure games developed by Flagship and published by Nintendo for the Game Boy Color. They are the seventh and eighth installments in the Legend of Zelda series.', 'https://media.retroachievements.org/Images/108279.png', 'https://media.retroachievements.org/Images/022647.png', 'https://media.retroachievements.org/Images/000070.png', 'https://media.retroachievements.org/Images/023377.png', 4.8),
  (6, 727, 'Pokémon Trading Card Game', 'Game Boy Color', 6, 4752, 4752, 4752, 35, 0, 'Strategy, Collectible Card Game', 'Hudson Soft', 'Media Factory', '1998-12-18', 'The Pokémon Trading Card Game , abbreviated as PTCG or Pokémon TCG, is a tabletop and collectible card game developed by Creatures Inc. based on the Pokémon franchise. Originally published in Japan by Media Factory in 1996, publishing worldwide is currently handled by The Pokémon Company. In the United States and also by Gopu, Pokémon TCG publishing was originally licensed to Wizards of the Coast, the producer of Magic: The Gathering. Wizards published eight expansion sets between 1998 and 2003, after which point licensing was transferred to The Pokémon Company.', 'https://media.retroachievements.org/Images/091409.png', 'https://media.retroachievements.org/Images/025779.png', 'https://media.retroachievements.org/Images/001771.png', 'https://media.retroachievements.org/Images/001772.png', 4.7),
  (7, 520, 'Metal Gear Solid: Ghost Babel', 'Game Boy Color', 6, 4421, 4421, 4421, 106, 0, 'Stealth', 'Konami', 'Konami', '2000-04-27', 'Metal Gear Solid, released in Japan as Metal Gear: Ghost Babel, is a 2000 action-adventure stealth game developed and published by Konami for the Game Boy Color. The game began development after Konami Computer Entertainment Japan were commissioned by Konami''s European branch to develop a portable adaptation of their 1998 PlayStation game of the same title. However, the Game Boy Color version is not a port of the original PlayStation version, nor does it adapt the same story, but instead takes place in an alternative continuity set seven years after the events of the original Metal Gear (1987). Tose assisted on the development. The game is set to be re-released for the first time via Metal Gear Solid: Master Collection Vol. 2 under its Japanese name.', 'https://media.retroachievements.org/Images/115935.png', 'https://media.retroachievements.org/Images/004437.png', 'https://media.retroachievements.org/Images/118045.png', 'https://media.retroachievements.org/Images/118046.png', 4.7),
  (8, 14221, 'Wario Land II', 'Game Boy Color', 6, 4188, 4188, 4188, 39, 0, '2D Platforming', NULL, 'Nintendo', '1998-10-21', 'Wario Land II, known in Japan as Wario Land 2: The Stolen Treasure, is a 1998 platform game developed and published by Nintendo for the Game Boy. Players control Wario as he sets out to recover his stolen treasure from Captain Syrup.', 'https://media.retroachievements.org/Images/112389.png', 'https://media.retroachievements.org/Images/045708.png', 'https://media.retroachievements.org/Images/113531.png', 'https://media.retroachievements.org/Images/113532.png', 4.7),
  (9, 722, 'Pokémon Silver Version', 'Game Boy Color', 6, 4133, 4133, 4133, 75, 0, NULL, NULL, NULL, '1999-11-21', 'Pokémon Gold Version and Pokémon Silver Version are 1999 role-playing video games developed by Game Freak and published by Nintendo for the Game Boy Color. They are the first installments in the second generation of the Pokémon video game series. They were released in Japan in 1999, Australia and North America in 2000, and Europe in 2001.', 'https://media.retroachievements.org/Images/105171.png', 'https://media.retroachievements.org/Images/000824.png', 'https://media.retroachievements.org/Images/028684.png', 'https://media.retroachievements.org/Images/028685.png', 4.7),
  (10, 3818, 'Dragon Quest I & II', 'Game Boy Color', 6, 3846, 3846, 3846, 73, 0, 'Compilation, Turn-Based RPG', 'TOSE', 'Enix', '2000-09-23', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/093949.png', 'https://media.retroachievements.org/Images/007624.png', 'https://media.retroachievements.org/Images/007625.png', 'https://media.retroachievements.org/Images/033863.png', 4.7),
  (11, 713, 'Mega Man Xtreme', 'Game Boy Color', 6, 3434, 3434, 3434, 44, 0, '2D Platforming', 'Capcom', 'Capcom', '2000-10-20', 'Mega Man Xtreme is a 2000 platform game developed and published by Capcom for the Game Boy Color. It is a spin-off title in the Mega Man X series of video games that originated on the Super Nintendo Entertainment System. Mega Man Xtreme takes place within the series timeline during the 22nd century, in which a group of "Maverick" androids called the "Shadow Hunters" hack into the world''s "Mother Computer" system, destabilize all of the networks, and allow other Mavericks to cause rampant destruction all over the world. The heroic "Maverick Hunter" X is tasked with going into cyberspace to relive his past missions and put a stop to the group''s plans.', 'https://media.retroachievements.org/Images/023366.png', 'https://media.retroachievements.org/Images/101634.png', 'https://media.retroachievements.org/Images/002546.png', 'https://media.retroachievements.org/Images/002547.png', 4.7),
  (12, 5062, '1942', 'Game Boy Color', 6, 3362, 3362, 3362, 18, 0, 'Shoot ''em Up', NULL, 'Capcom', '2000-05-01', '1942 (MCMXLII) was a common year starting on Thursday of the Gregorian calendar, the 1942nd year of the Common Era (CE) and Anno Domini (AD) designations, the 942nd year of the 2nd millennium, the 42nd year of the 20th century, and the 3rd year of the 1940s decade. ', 'https://media.retroachievements.org/Images/063512.png', 'https://media.retroachievements.org/Images/025219.png', 'https://media.retroachievements.org/Images/063872.png', 'https://media.retroachievements.org/Images/063873.png', 4.7),
  (13, 726, 'Pokémon Puzzle Challenge', 'Game Boy Color', 6, 2641, 2641, 2641, 62, 0, 'Tile Matching', 'Intelligent Systems', 'Nintendo', '2000-09-21', 'Pokémon Puzzle Challenge is a puzzle video game developed by Intelligent Systems and published by Nintendo for the Game Boy Color. It was released in Japan on September 21, 2000; in North America on December 4, 2000; and in PAL regions on June 15, 2001, it is the second Pokémon-themed entry in the Puzzle League series. While its Nintendo 64 counterpart Pokémon Puzzle League is visually based on the Pokemon anime, Puzzle Challenge instead draws inspiration from the Pokémon Gold and Silver games. The game features multiple modes of play and support for competitive play between two players. Puzzle Challenge was later digitally re-released via the Nintendo 3DS''s Virtual Console line on November 6, 2014.', 'https://media.retroachievements.org/Images/070464.png', 'https://media.retroachievements.org/Images/026318.png', 'https://media.retroachievements.org/Images/006025.png', 'https://media.retroachievements.org/Images/006026.png', 4.6),
  (14, 741, 'Wario Land 3', 'Game Boy Color', 6, 2324, 2324, 2324, 106, 0, '2D Platforming', NULL, 'Nintendo', '2000-03-21', 'Wario Land 3, known in Japan as Wario Land 3: Mysterious Music Box, is a 2000 platform game developed by Nintendo R&D1 and published by Nintendo for the Game Boy Color. The game''s plot centers around Wario who must free a mysterious figure who is trapped inside a music box. The game was released in Japan on March 21, 2000, Europe on April 14, 2000, and North America on May 30, 2000.', 'https://media.retroachievements.org/Images/112290.png', 'https://media.retroachievements.org/Images/001507.png', 'https://media.retroachievements.org/Images/113601.png', 'https://media.retroachievements.org/Images/113602.png', 4.6),
  (15, 4129, 'Frogger', 'Game Boy Color', 6, 1880, 1880, 1880, 12, 0, 'Arcade', 'Morning Star Multimedia', 'Majesco Entertainment', '1998-12-31', 'Frogger is a 1981 action video game developed by Konami and published by Sega for arcades. It was released in North America by Sega/Gremlin. The object of the game is to direct five frogs to their homes by dodging traffic on a busy road, then crossing a river by jumping on floating logs, turtles, and alligators.', 'https://media.retroachievements.org/Images/073198.png', 'https://media.retroachievements.org/Images/008056.png', 'https://media.retroachievements.org/Images/044698.png', 'https://media.retroachievements.org/Images/044699.png', 4.6),
  (16, 1403, 'Mario Golf', 'Game Boy Color', 6, 1759, 1759, 1759, 44, 0, 'Sports - Golf', 'Camelot Software Planning', 'Nintendo', '1999-08-10', '  There have been numerous sports games featuring Mario characters, based, among others, on tennis, golf, baseball, soccer, and various sports featured in the Olympic Games.', 'https://media.retroachievements.org/Images/080115.png', 'https://media.retroachievements.org/Images/079813.png', 'https://media.retroachievements.org/Images/007086.png', 'https://media.retroachievements.org/Images/008375.png', 4.6),
  (17, 5043, 'Mario Tennis', 'Game Boy Color', 6, 1726, 1726, 1726, 70, 0, 'Sports - Tennis', 'Camelot Software Planning', 'Nintendo', '2000-11-01', 'Mario Tennis is a 2000 sports video game developed by Camelot Software Planning and published by Nintendo for the Nintendo 64 (N64). Following Mario''s Tennis, it is the second game in the Mario Tennis series. The game is known for being the debut game of Luigi''s arch-rival, Waluigi, and the re-introduction of Princess Daisy and Birdo.', 'https://media.retroachievements.org/Images/080421.png', 'https://media.retroachievements.org/Images/014522.png', 'https://media.retroachievements.org/Images/014526.png', 'https://media.retroachievements.org/Images/014527.png', 4.5),
  (18, 697, 'Dragon Quest III', 'Game Boy Color', 6, 1699, 1699, 1699, 138, 0, 'Turn-Based RPG', 'TOSE', 'Enix', '2000-12-08', 'Dragon Quest III: The Seeds of Salvation, titled Dragon Warrior III when initially localized to North America, is a 1988 role-playing video game developed by Chunsoft and published by Enix. It is the third installment in the Dragon Quest series and was first released for the Family Computer (Famicom) in Japan and later for the Nintendo Entertainment System (NES) in North America. The game saw an enhanced remake for the Super Famicom in 1996 and the Game Boy Color in 2001, and a port to mobile phones and the Wii in 2009 and 2011. A version of the game for Android and iOS was released in Japan on September 25, 2014, and worldwide as Dragon Quest III: The Seeds of Salvation on December 4, 2014. It was the first time the game was given an official English subtitle. Later in 2021, another remake of the game titled Dragon Quest III HD-2D Remake, based on the HD-2D graphical style of Octopath Traveler (2018), was announced during the franchise''s 35th anniversary livestream. The remake was released on November 14th, 2024 for Nintendo Switch, PlayStation 5, Windows, and Xbox Series consoles.', 'https://media.retroachievements.org/Images/067978.png', 'https://media.retroachievements.org/Images/007628.png', 'https://media.retroachievements.org/Images/059408.png', 'https://media.retroachievements.org/Images/059947.png', 4.5),
  (19, 8569, 'Mr. Driller', 'Game Boy Color', 6, 1636, 1636, 1636, 12, 0, 'Puzzle', 'Namco', 'Namco', '2000-08-02', 'Mr. Driller is a puzzle video game franchise created by Yasuhito Nagaoka and Hideo Yoshizawa for Namco. The eponymous first game was released in 1999 for arcades and several home consoles, such as the PlayStation. Gameplay in the series consists of controlling Susumu Hori, the titular Mr. Driller, or one of his friends and destroying colorful formations of blocks to make it to the bottom of a well. In order to survive, players need to collect air capsules to replenish their depleting oxygen and avoid being crushed by falling blocks.', 'https://media.retroachievements.org/Images/086250.png', 'https://media.retroachievements.org/Images/083139.png', 'https://media.retroachievements.org/Images/083137.png', 'https://media.retroachievements.org/Images/083138.png', 4.5),
  (20, 7107, 'Bomberman Max: Blue Champion', 'Game Boy Color', 6, 1558, 1558, 1558, 40, 0, 'Puzzle', 'Hudson Soft', 'Vatical Entertainment', '2000-05-14', 'Bomberman Max: Blue Champion and Bomberman Max: Red Challenger are video games released for the Game Boy Color on May 9, 2000. The game was followed by Bomberman Max 2 which was released for the Game Boy Advance on June 4, 2002. There are two versions called Bomberman Max: Blue Champion and Bomberman Max: Red Challenger. In Blue Champion the playable character is Bomberman where in Red Challenger the playable character is Max.', 'https://media.retroachievements.org/Images/051740.png', 'https://media.retroachievements.org/Images/007088.png', 'https://media.retroachievements.org/Images/044822.png', 'https://media.retroachievements.org/Images/044823.png', 4.5),
  (21, 13389, '~Hack~ Crystal Clear', 'Game Boy Color', 6, 1502, 1502, 1502, 195, 0, 'Turn-Based RPG', 'ShockSlayer', 'Hack - Pokemon Crystal Version', '2019-08-03', 'Pokémon Crystal Version is a role-playing video game developed by Game Freak and published by Nintendo for the Game Boy Color, released in Japan in December 2000 and internationally throughout 2001. Serving as an enhanced edition of the 1999 titles Pokémon Gold and Silver, it is the final entry in the second generation of the Pokémon game series. The game introduced several new features, including additional story elements, a Battle Tower area, the option to play as a female protagonist, animated Pokémon sprites during battles, and various minor improvements. The Japanese version of the game also utilized the capabilities of the Mobile Adapter GB, a peripheral that allowed players to trade and battle over cell phones and a paid subscription service called "Mobile System GB". These enhancements were made possible by the Game Boy Color''s improved hardware, making Crystal the first game in the series to be incompatible with the original Game Boy.', 'https://media.retroachievements.org/Images/066026.png', 'https://media.retroachievements.org/Images/026913.png', 'https://media.retroachievements.org/Images/019682.png', 'https://media.retroachievements.org/Images/027061.png', 4.5),
  (22, 16597, '~Prototype~ Pokémon Picross', 'Game Boy Color', 6, 1502, 1502, 1502, 17, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1999-01-01', 'Pokémon Picross  is a freemium puzzle video game featuring Pokémon characters developed by Jupiter Corporation and published by Nintendo and The Pokémon Company for the Nintendo 3DS. The title is part of the "Picross" nonogram series that use number-based grid puzzles to reveal pictures. It was released as a downloadable title on the Nintendo 3DS eShop worldwide in December 2015.', 'https://media.retroachievements.org/Images/121546.png', 'https://media.retroachievements.org/Images/051333.png', 'https://media.retroachievements.org/Images/037089.png', 'https://media.retroachievements.org/Images/037090.png', 4.5),
  (23, 2501, 'Astérix & Obélix', 'Game Boy Color', 6, 1449, 1449, 1449, 46, 0, '2D Platforming', 'Bit Managers', 'Infogrames', '1999-01-01', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/048473.png', 'https://media.retroachievements.org/Images/008760.png', 'https://media.retroachievements.org/Images/044704.png', 'https://media.retroachievements.org/Images/044705.png', 4.5),
  (24, 3608, 'Dragon Quest Monsters', 'Game Boy Color', 6, 1435, 1435, 1435, 64, 0, 'Turn-Based RPG', 'TOSE', 'Eidos Interactive', '1998-09-25', 'Dragon Quest Monsters is a spin-off series of the Dragon Quest games. Primarily developed by Tose and published by Square Enix, it sets the player in a medieval/fantasy world filled with magic, monsters, and knights. Unlike the original Dragon Quest games, the player''s character does not do any of the fighting in battles; the player must instead rely on capturing, breeding, and raising monsters to do the fighting for them. The concept originated from Dragon Quest V (1992). The character and monster designs are by Dragon Ball creator Akira Toriyama. The series spans several handheld gaming systems, and each game has received positive reviews from critics. The series'' gameplay has been compared to Pokémon.', 'https://media.retroachievements.org/Images/086568.png', 'https://media.retroachievements.org/Images/037700.png', 'https://media.retroachievements.org/Images/007285.png', 'https://media.retroachievements.org/Images/007287.png', 4.5),
  (25, 5185, '10-Pin Bowling', 'Game Boy Color', 6, 1405, 1405, 1405, 6, 0, 'Sports - Bowling', 'Morning Star Multimedia', 'Majesco Entertainment', '1999-08-01', 'Tenpin bowling is a type of bowling in which a bowler rolls a bowling ball down a wood or synthetic lane toward ten pins positioned evenly in four rows in an equilateral triangle. The goal is to knock down all ten pins on the first delivery, or failing that, on the second delivery. While most people approach modern tenpin bowling as a simple recreational pastime, those who bowl competitively, especially at the highest levels, consider it a demanding sport requiring precision and skill. A 15-foot (5 m) long approach area is used by the bowler to impart speed and apply side rotation to the bowling ball and is separated from the lane by a foul line. Crossing this foul line is detectable via sensors and results in a score of zero for the delivery in league or tournament play. The 41.5-inch-wide (105 cm), 60-foot-long (18 m) lane is bordered along its length by gutters (channels) that collect errant balls. The lane''s long and narrow shape limits straight-line ball paths to angles that are shallower than the ideal entry angle(s) for achieving strikes; accordingly, bowlers impart side rotation to hook (curve) the ball into the pins to increase the likelihood of striking.', 'https://media.retroachievements.org/Images/036471.png', 'https://media.retroachievements.org/Images/036076.png', 'https://media.retroachievements.org/Images/036075.png', 'https://media.retroachievements.org/Images/036510.png', 4.5),
  (26, 3607, 'Street Fighter Alpha: Warriors'' Dreams', 'Game Boy Color', 6, 1400, 1400, 1400, 30, 0, '2D Fighting', 'Crawfish Interactive', 'Capcom', '2000-03-24', 'Street Fighter Alpha: Warriors'' Dreams, known as Street Fighter Zero in Japan, Asia, South America, and Oceania, is a 1995 fighting game developed and published by Capcom for arcades. It was the first all-new Street Fighter game produced by Capcom since 1991''s Street Fighter II. Plotwise, it serves as a prequel to Street Fighter II and thus features younger versions of established characters, as well as characters from the original Street Fighter and Final Fight.', 'https://media.retroachievements.org/Images/079116.png', 'https://media.retroachievements.org/Images/007512.png', 'https://media.retroachievements.org/Images/007509.png', 'https://media.retroachievements.org/Images/007510.png', 4.5),
  (27, 5133, 'Resident Evil: Gaiden', 'Game Boy Color', 6, 1233, 1233, 1233, 34, 0, 'Action-Adventure, Survival Horror', 'Capcom, M4', 'Capcom, Virgin Interactive', '2001-12-14', 'Resident Evil Gaiden is a 2001 action-adventure game developed by M4 for the Game Boy Color. It was published by Capcom in Japan and North America, and by Virgin Interactive in Europe. Receiving generally mixed reviews by critics, the game marks a departure from other entries in the series, insofar as areas are explored with the playable character seen from a top-down perspective and with battles fought in first-person view. The story revolves around a viral outbreak on a passenger ship and has Leon S. Kennedy and Barry Burton return as protagonists. This game is non-canon, as its plot is contradicted by the main series in key parts, and its events are ignored.', 'https://media.retroachievements.org/Images/034861.png', 'https://media.retroachievements.org/Images/047498.png', 'https://media.retroachievements.org/Images/003392.png', 'https://media.retroachievements.org/Images/003393.png', 4.5),
  (28, 14165, 'Sesame Street: Elmo''s ABCs', 'Game Boy Color', 6, 1213, 1213, 1213, 6, 0, 'Educational', 'Bonsai Entertainment', 'NewKidCo', '1999-03-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/042255.png', 'https://media.retroachievements.org/Images/042039.png', 'https://media.retroachievements.org/Images/053887.png', 'https://media.retroachievements.org/Images/053888.png', 4.5),
  (29, 537, 'Rayman', 'Game Boy Color', 6, 1207, 1207, 1207, 34, 0, '2D Platforming', 'Ubisoft', 'Ubisoft', '2000-03-29', 'Rayman is a franchise of platformer video games, created by video game designer Michel Ancel for Ubisoft. Since the release of Rayman in 1995, the series has produced a total of 45 games across multiple platforms.', 'https://media.retroachievements.org/Images/110514.png', 'https://media.retroachievements.org/Images/056859.png', 'https://media.retroachievements.org/Images/001015.png', 'https://media.retroachievements.org/Images/001016.png', 4.5),
  (30, 9725, 'Wendy: Every Witch Way', 'Game Boy Color', 6, 1205, 1205, 1205, 37, 0, '2D Platforming', 'WayForward', 'TDK Mediactive', '2001-08-28', 'Wendy: Every Witch Way is an action platform video game published by TDK Mediactive and developed by WayForward Technologies for the Game Boy Color in 2001. The game centers on Wendy the Good Little Witch from the Casper the Friendly Ghost series. Wendy accidentally opens her aunts'' chest containing magical stones, which upset the gravity of a floating castle that crashes onto her house. The player controls Wendy through four worlds with sixteen levels, with each world having three side-scrolling levels and one horizontal shooter stage. Inserting the game in the Game Boy Advance unlocks a new world exclusive to the console.', 'https://media.retroachievements.org/Images/109829.png', 'https://media.retroachievements.org/Images/022910.png', 'https://media.retroachievements.org/Images/029387.png', 'https://media.retroachievements.org/Images/022907.png', 4.5),
  (31, 4912, 'Mega Man Xtreme 2', 'Game Boy Color', 6, 1155, 1155, 1155, 44, 0, '2D Platforming', 'Capcom', 'Capcom', '2001-07-19', 'Mega Man Xtreme 2 is a 2001 platform game developed and published by Capcom for the Game Boy Color. It is a spin-off title in the Mega Man X series and a follow-up to Mega Man Xtreme, which was released the previous year. Mega Man Xtreme 2 is set in the 22nd century between the events of Mega Man X3 and Mega Man X4. The DNA souls of robots known as "Reploids" are being stolen and used to create an army of undead "Mavericks". The "Maverick Hunters" X and Zero quickly spring into action with the help of their young ally Iris.', 'https://media.retroachievements.org/Images/023367.png', 'https://media.retroachievements.org/Images/002568.png', 'https://media.retroachievements.org/Images/102856.png', 'https://media.retroachievements.org/Images/102857.png', 4.5),
  (32, 24124, '~Homebrew~ Slender: The 8 Pages', 'Game Boy Color', 6, 1150, 1150, 1150, 9, 0, NULL, 'JWG.LLC', 'itch.io', '2021-11-14', 'Slender: The Eight Pages, originally titled Slender, is a first-person survival horror game based on Slender Man, a well-known creepypasta. Influenced by the web series Marble Hornets, it was developed by independent developer Mark J. Hadley using the Unity game engine and was released in June 2012 by his one-man studio, Parsec Productions. He drew inspiration from Amnesia: The Dark Descent''s atmosphere and imagery, though opted for random encounters, rather than Amnesia’s linear design, which Hadley felt diminished its sense of horror.', 'https://media.retroachievements.org/Images/071726.png', 'https://media.retroachievements.org/Images/071725.png', 'https://media.retroachievements.org/Images/084370.png', 'https://media.retroachievements.org/Images/084373.png', 4.5),
  (33, 7687, 'Caterpillar Construction Zone', 'Game Boy Color', 6, 1139, 1139, 1139, 15, 0, 'Job Simulation', 'Realtime Associates', 'Mattel', '2000-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/122051.png', 'https://media.retroachievements.org/Images/032119.png', 'https://media.retroachievements.org/Images/032118.png', 'https://media.retroachievements.org/Images/032117.png', 4.5),
  (34, 13427, 'Sesame Street: Elmo''s 123s', 'Game Boy Color', 6, 1119, 1119, 1119, 6, 0, 'Educational', 'Bonsai Entertainment', 'NewKidCo', '1999-03-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/116382.png', 'https://media.retroachievements.org/Images/042036.png', 'https://media.retroachievements.org/Images/059337.png', 'https://media.retroachievements.org/Images/059338.png', 4.5),
  (35, 22589, '~Homebrew~ A 20 Second Platformer', 'Game Boy Color', 6, 987, 987, 987, 6, 0, '2D Platforming', 'allalonegamez', 'itch.io', '2022-11-24', 'Little Nicky is a 2000 licensed platform game developed by Digital Eclipse and published by Ubisoft for the Game Boy Color. Based on the comedy film of the same name, the game was released exclusively in North America. The player controls the half-demon/angel Nicky and utilizes his demonic powers in order to traverse 24 levels inspired by events from the titular film. Outside of the main game, the player can also partake in five different minigames. Critical reception towards the game was mixed, with many reviewers praising its visuals and risqué elements, while a myriad of reactions were given towards the game''s audio and gameplay.', 'https://media.retroachievements.org/Images/092885.png', 'https://media.retroachievements.org/Images/083276.png', 'https://media.retroachievements.org/Images/071830.png', 'https://media.retroachievements.org/Images/071831.png', 4.4),
  (36, 5065, 'Pac-Man: Special Color Edition', 'Game Boy Color', 6, 982, 982, 982, 50, 0, 'Arcade, Maze Chase', 'Namco', 'Namco', '1999-08-01', 'Pac-Man is a video game series and media franchise developed, published and owned by Bandai Namco Entertainment, a video game publisher that was previously known as Namco. Entries have been developed by a wide array of other video game companies, including Midway Games, Atari and Mass Media, Inc., and was created by Toru Iwatani. The first entry in the series was released in arcades in 1980 by Namco, and published by Midway Games in North America. Most Pac-Man games are maze chase games, but it has also delved into other genres, such as platformers, racing, and sports. Several games in the series were released for a multitude of home consoles and are included in many Bandai Namco video game compilations.', 'https://media.retroachievements.org/Images/071502.png', 'https://media.retroachievements.org/Images/051552.png', 'https://media.retroachievements.org/Images/070424.png', 'https://media.retroachievements.org/Images/070423.png', 4.4),
  (37, 6385, 'Crystalis', 'Game Boy Color', 6, 972, 972, 972, 57, 0, NULL, NULL, 'Nintendo', '2000-06-26', 'Crystalis is a 1990 action role-playing video game developed and published by SNK for the Nintendo Entertainment System. A port for the Game Boy Color developed by Nintendo Software Technology and published by Nintendo was released in 2000.', 'https://media.retroachievements.org/Images/083493.png', 'https://media.retroachievements.org/Images/045607.png', 'https://media.retroachievements.org/Images/065197.png', 'https://media.retroachievements.org/Images/065198.png', 4.4),
  (38, 30725, '~Homebrew~ Hatsune Miku Bomb Squad', 'Game Boy Color', 6, 970, 970, 970, 6, 0, NULL, 'birdup', 'birdup', '2024-08-07', 'This is a list of notable video game companies that have made games for either computers, video game consoles, handheld or mobile devices, and includes companies that currently exist as well as now-defunct companies.', 'https://media.retroachievements.org/Images/101115.png', 'https://media.retroachievements.org/Images/101118.png', 'https://media.retroachievements.org/Images/101116.png', 'https://media.retroachievements.org/Images/101117.png', 4.4),
  (39, 16191, '~Hack~ Pokémon Polished Crystal', 'Game Boy Color', 6, 966, 966, 966, 173, 0, 'Turn-Based RPG', 'Rangi', 'Hack - Pokemon Crystal Version', '2016-09-20', '1998 saw many sequels and prequels in video games, such as The Legend of Zelda: Ocarina of Time, Metal Gear Solid, Resident Evil 2, Crash Bandicoot: Warped, F-Zero X, Fallout 2, Gex: Enter the Gecko, Marvel vs. Capcom: Clash of Super Heroes, Panzer Dragoon Saga, Return to Krondor, Sonic Adventure, Soulcalibur, Street Fighter Alpha 3, and Tomb Raider III, along with new titles such as Banjo-Kazooie, Dance Dance Revolution, Half-Life, MediEvil, Parasite Eve, Radiant Silvergun, Spyro the Dragon, StarCraft and Xenogears. In Japan, Sega released the Dreamcast which was the first console of the sixth generation and also the company''s last major console.', 'https://media.retroachievements.org/Images/123087.png', 'https://media.retroachievements.org/Images/033006.png', 'https://media.retroachievements.org/Images/123588.png', 'https://media.retroachievements.org/Images/123589.png', 4.4),
  (40, 9491, '~Hack~ Pokémon Prism Version', 'Game Boy Color', 6, 964, 964, 964, 94, 0, NULL, 'Koolboyman, RainbowDevs', NULL, '2016-12-19', 'Pokémon Prism is a fanmade video game based on the Pokémon series. A ROM hack of Pokémon Crystal (2000), it was developed by Adam Vierra, also known by his online pseudonym "Koolboyman", alongside a team of numerous developers. The game is a sequel to his prior hack, Pokémon Brown (2004), and centers on the child of Lance, a boss of Pokémon Gold and Silver (1999), as the protagonist. The premise follows the protagonist as they find themselves in the region of Naljo after an earthquake and attempt to defeat Naljo''s Pokémon League.', 'https://media.retroachievements.org/Images/113781.png', 'https://media.retroachievements.org/Images/015728.png', 'https://media.retroachievements.org/Images/025790.png', 'https://media.retroachievements.org/Images/032725.png', 4.4),
  (41, 31200, '~Homebrew~ Super Mario Bros. Mini', 'Game Boy Color', 6, 934, 934, 934, 75, 0, '2D Platforming', 'Mico27', 'itch.io', '2024-10-26', 'Super Mario Bros. Deluxe is a 1999 platform game developed and published by Nintendo for the Game Boy Color. It is a largely unaltered port of the 1985 Super Mario Bros., originally released for the Nintendo Entertainment System (NES), with an unlockable version of its 1986 Japanese sequel, Super Mario Bros.: The Lost Levels. The game also introduces several new features, including a single-player and two-player race mode, a challenge mode for individual levels, and various toys and collectibles, some of which utilize the functionality of the Game Boy Printer.', 'https://media.retroachievements.org/Images/103697.png', 'https://media.retroachievements.org/Images/103700.png', 'https://media.retroachievements.org/Images/103692.png', 'https://media.retroachievements.org/Images/103693.png', 4.4),
  (42, 4893, 'Conker''s Pocket Tales', 'Game Boy Color', 6, 933, 933, 933, 35, 0, 'Action-Adventure', 'Rare', 'Nintendo', '1999-06-08', 'Conker''s Pocket Tales is a 1999 action-adventure game developed and published by Rare for the Game Boy Color. It is the first game in the Conker series and follows the story of Conker the Squirrel as he retrieves his stolen birthday presents and rescues his girlfriend Berri, who has been kidnapped by the Evil Acorn. The cartridge is dual-format, allowing it to also run on the original Game Boy with some gameplay differences.', 'https://media.retroachievements.org/Images/114693.png', 'https://media.retroachievements.org/Images/064301.png', 'https://media.retroachievements.org/Images/002714.png', 'https://media.retroachievements.org/Images/002713.png', 4.4),
  (43, 5021, 'Donkey Kong Country', 'Game Boy Color', 6, 913, 913, 913, 38, 0, '2D Platforming', 'Rare', 'Nintendo', '2000-11-05', 'Donkey Kong Country, known in Japan as Super Donkey Kong, is a 1994 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It follows the gorilla Donkey Kong and his nephew Diddy Kong as they set out to recover their stolen banana hoard from the crocodile King K. Rool and his army, the Kremlings. The player traverses 40 side-scrolling levels as they jump between platforms and avoid obstacles. They collect items, ride minecarts and animals, defeat enemies and bosses, and find secret bonus stages. In multiplayer modes, two players work cooperatively or race.', 'https://media.retroachievements.org/Images/046978.png', 'https://media.retroachievements.org/Images/015523.png', 'https://media.retroachievements.org/Images/015524.png', 'https://media.retroachievements.org/Images/015525.png', 4.4),
  (44, 4056, 'Legend of the River King GBC', 'Game Boy Color', 6, 910, 910, 910, 57, 0, 'Sports - Fishing', 'Marvelous Interactive', 'Natsume, Marvelous Interactive', '1999-11-01', 'Harvest Moon 2 GBC, released in Japan as Bokujō Monogatari GB2 (牧場物語GB2), is a farming simulation video game for the Game Boy Color developed and published by Victor Interactive Software, and the second portable game in the Story of Seasons series. The object of the game is to cultivate a farm to prevent the land from being used to build an amusement park. As with the previous game, the player may choose to play as a boy or a girl.', 'https://media.retroachievements.org/Images/036380.png', 'https://media.retroachievements.org/Images/036091.png', 'https://media.retroachievements.org/Images/044542.png', 'https://media.retroachievements.org/Images/044543.png', 4.4),
  (45, 4933, 'Shadowgate Classic', 'Game Boy Color', 6, 853, 853, 853, 33, 0, 'Dungeon Crawl, Point-and-Click Adventure', 'Infinite Ventures', 'Nintendo', '1999-01-01', 'Shadowgate is a 1987 point-and-click adventure game developed by ICOM Simulations and published by Mindscape for the Macintosh as part of the MacVenture series. The game takes place in the Castle Shadowgate, residence of the evil Warlock Lord. The player, as the "last of a great line of hero-kings", is tasked with saving the world by defeating the Warlock Lord, who is attempting to summon the demon Behemoth out of Hell. The original Macintosh version was only in black-and-white, but color versions of the game were later released for the Amiga and Atari ST, and in 1989 for the Nintendo Entertainment System. The game was generally well-received, and was followed by several sequels and remakes for various systems.', 'https://media.retroachievements.org/Images/064429.png', 'https://media.retroachievements.org/Images/021896.png', 'https://media.retroachievements.org/Images/003245.png', 'https://media.retroachievements.org/Images/003243.png', 4.4),
  (46, 2818, 'Harry Potter and the Chamber of Secrets', 'Game Boy Color', 6, 841, 841, 841, 72, 0, NULL, 'Griptonite Games', 'Electronic Arts', '2002-11-01', 'Harry Potter and the Chamber of Secrets is a fantasy novel by British author J. K. Rowling. The second novel in the Harry Potter series, it chronicles Harry Potter''s second year at Hogwarts School of Witchcraft and Wizardry. After several residents of the school are attacked and magically immobilised, Harry and his friends Ron and Hermione investigate.', 'https://media.retroachievements.org/Images/085763.png', 'https://media.retroachievements.org/Images/007709.png', 'https://media.retroachievements.org/Images/020296.png', 'https://media.retroachievements.org/Images/020297.png', 4.4),
  (47, 19541, '~Homebrew~ Castlevania: Circle of the Moon - GBC Edition', 'Game Boy Color', 6, 832, 832, 832, 7, 0, 'Metroidvania', 'Ryan Marcham', 'Ryan Marcham', '2022-04-28', 'The following is a comprehensive index of all games released in 2023, sorted chronologically by release date, and divided by quarter. Information regarding developer, publisher, operating system, genre, and type of release is provided where available', 'https://media.retroachievements.org/Images/088301.png', 'https://media.retroachievements.org/Images/058030.png', 'https://media.retroachievements.org/Images/057544.png', 'https://media.retroachievements.org/Images/069974.png', 4.4),
  (48, 5594, 'Dragon Ball Z: Legendary Super Warriors', 'Game Boy Color', 6, 793, 793, 793, 81, 0, 'Card Game, Turn-Based RPG', 'Flight-Plan', 'Banpresto, Infogrames', '2002-06-28', 'Dragon Ball Z: Legendary Super Warriors is a turn-based fighting game released for the Game Boy Color. It is played with the use of in-game cards for attacks, techniques and support items. The game''s story takes place from the start of Dragon Ball Z, the Saiyan Saga, and runs until the end of the Buu Saga. The game includes two extra stories involving Future Trunks''s timeline.', 'https://media.retroachievements.org/Images/121631.png', 'https://media.retroachievements.org/Images/121092.png', 'https://media.retroachievements.org/Images/120941.png', 'https://media.retroachievements.org/Images/120942.png', 4.4),
  (49, 4871, 'Centipede', 'Game Boy Color', 6, 735, 735, 735, 17, 0, 'Arcade, Shoot ''em Up', 'Accolade', 'Majesco Entertainment', '1998-11-30', 'Centipedes are predatory arthropods belonging to the class Chilopoda of the subphylum Myriapoda, an arthropod group which includes millipedes and other multi-legged animals. Centipedes are elongated segmented (metameric) animals with one pair of legs per body segment. All centipedes are venomous and can inflict painful stings, injecting their venom through pincer-like appendages known as forcipules or toxicognaths, which are actually modified legs instead of fangs. Despite the name, no species of centipede has exactly 100 legs; the number of pairs of legs is an odd number that ranges from 15 pairs to 191 pairs.', 'https://media.retroachievements.org/Images/056480.png', 'https://media.retroachievements.org/Images/010910.png', 'https://media.retroachievements.org/Images/010912.png', 'https://media.retroachievements.org/Images/010922.png', 4.4),
  (50, 5067, 'Pong: The Next Level', 'Game Boy Color', 6, 728, 728, 728, 18, 0, 'Arcade', 'Morning Star Multimedia', 'Hasbro Interactive', '1999-12-01', 'Pong: The Next Level is a 1999 table tennis video game serving as a remake of the 1972 Atari game Pong. It was developed by Supersonic Software and published by Hasbro Interactive for the PlayStation and Microsoft Windows, and was later ported to Game Boy Color and Mac OS.', 'https://media.retroachievements.org/Images/021495.png', 'https://media.retroachievements.org/Images/021513.png', 'https://media.retroachievements.org/Images/021515.png', 'https://media.retroachievements.org/Images/021516.png', 4.4),
  (51, 4126, 'WWF Betrayal', 'Game Boy Color', 6, 725, 725, 725, 15, 0, 'Wrestling', 'WayForward', 'THQ', '2001-08-07', 'WWF Betrayal is a beat ''em up on the Game Boy Color based on the World Wrestling Federation (WWF). It was the third and last WWF game released to the Game Boy Color and one of a few games based on the promotion that was of a different genre than the regular professional wrestling games usually produced.', 'https://media.retroachievements.org/Images/077219.png', 'https://media.retroachievements.org/Images/026380.png', 'https://media.retroachievements.org/Images/026381.png', 'https://media.retroachievements.org/Images/026382.png', 4.4),
  (52, 4131, 'Sesame Street Sports', 'Game Boy Color', 6, 695, 695, 695, 18, 0, '2D Platforming', 'Bonsai Entertainment', 'NewKidCo', '2001-11-15', ' There have been a variety of Sesame Street video games released for video game platforms. Most of the Sesame Street video games were published and developed by NewKidCo.', 'https://media.retroachievements.org/Images/043448.png', 'https://media.retroachievements.org/Images/041808.png', 'https://media.retroachievements.org/Images/052117.png', 'https://media.retroachievements.org/Images/052118.png', 4.4),
  (53, 4928, 'SpongeBob SquarePants: Legend of the Lost Spatula', 'Game Boy Color', 6, 677, 677, 677, 30, 0, '2D Platforming, Action', 'Vicarious Visions', 'THQ', '2001-03-15', 'SpongeBob SquarePants: Legend of the Lost Spatula is a 2001 platform action video game developed by Vicarious Visions and published by THQ for the Game Boy Color handheld game console. It is the first video game to be based on SpongeBob SquarePants. The game''s story centers on SpongeBob SquarePants, a sea sponge who lives in the undersea town of Bikini Bottom and works for Mr. Krabs as the fry cook of the Krusty Krab fast food restaurant. SpongeBob is destined to become the ocean''s greatest fry cook, and must embark on a quest to retrieve a golden spatula from the Flying Dutchman, a pirate ghost. The game features platforming-style gameplay, as well as many characters from the television series.', 'https://media.retroachievements.org/Images/105968.png', 'https://media.retroachievements.org/Images/007930.png', 'https://media.retroachievements.org/Images/033882.png', 'https://media.retroachievements.org/Images/033868.png', 4.4),
  (54, 1351, 'Scooby-Doo! Classic Creep Capers', 'Game Boy Color', 6, 672, 672, 672, 15, 0, 'Point-and-Click Adventure', 'Digital Eclipse', 'THQ', '2001-02-12', 'Scooby-Doo! Classic Creep Capers is an adventure game published by THQ for the Nintendo 64 and Game Boy Color, based on the Hanna-Barbera cartoon Scooby-Doo, Where Are You!. The Nintendo 64 version, developed by Terraglyph Interactive Studios, was released in November 2000, while the Game Boy Color version was developed by Digital Eclipse Software, and released in February 2001. A PlayStation version, identical to the Nintendo 64 version, had been in development by Terraglyph Interactive Studios but was later cancelled.', 'https://media.retroachievements.org/Images/084492.png', 'https://media.retroachievements.org/Images/070630.png', 'https://media.retroachievements.org/Images/070635.png', 'https://media.retroachievements.org/Images/070636.png', 4.4),
  (55, 18962, '~Homebrew~ Opossum Country', 'Game Boy Color', 6, 671, 671, 671, 6, 0, 'Horror', 'Ben Jelter', 'Ben Jelter', '2020-12-14', 'Opossums are members of the marsupial order Didelphimorphia endemic to the Americas. The largest order of marsupials in the Western Hemisphere, it comprises 126 species in 18 genera. Opossums originated in South America and entered North America in the Great American Interchange following the connection of North and South America in the late Cenozoic.', 'https://media.retroachievements.org/Images/068476.png', 'https://media.retroachievements.org/Images/111660.png', 'https://media.retroachievements.org/Images/111661.png', 'https://media.retroachievements.org/Images/111662.png', 4.4),
  (56, 4923, 'Survival Kids', 'Game Boy Color', 6, 647, 647, 647, 39, 0, 'Action RPG, Survival', 'Konami', 'Konami', '1999-10-01', 'Survival Kids, known as Stranded Kids in Europe, is a 1999 survival video game developed and published by Konami for the Game Boy Color. The gameplay revolves around surviving on a deserted island, and features an open-ended structure that presents the player with multiple ways to progress. It is the first in the Survival Kids series in Japan, which goes under the name Lost in Blue in North America and Europe.', 'https://media.retroachievements.org/Images/064496.png', 'https://media.retroachievements.org/Images/002679.png', 'https://media.retroachievements.org/Images/002680.png', 'https://media.retroachievements.org/Images/002712.png', 4.4),
  (57, 11673, 'Microsoft: The Best of Entertainment Pack', 'Game Boy Color', 6, 632, 632, 632, 27, 0, 'Minigames', 'Microsoft, Saffire Corporation, Cryo Interactive', 'Microsoft', '2001-05-30', 'Microsoft Entertainment Pack, also known as Windows Entertainment Pack or simply WEP, is a collection of 16-bit casual computer games for Windows. There were four Entertainment Packs released between 1990 and 1992. These games were somewhat unusual for the time, in that they would not run under MS-DOS. In 1994, a compilation of selected games from the previous four Entertainment Packs was released called The Best of Microsoft Entertainment Pack. A Game Boy Color version was released in 2001.', 'https://media.retroachievements.org/Images/017989.png', 'https://media.retroachievements.org/Images/017987.png', 'https://media.retroachievements.org/Images/017984.png', 'https://media.retroachievements.org/Images/017985.png', 4.4),
  (58, 10659, 'Barbie: Ocean Discovery', 'Game Boy Color', 6, 611, 611, 611, 21, 0, 'Puzzle / Action / Exploration', 'Realtime Associates', 'Mattel', '1999-05-01', 'Barbie, a fashion doll manufactured by American toy and entertainment company Mattel, has starred in numerous video games on PC, various console systems, IOS, and Android. Some games are adaptations of Barbie films or TV series, while others feature original storylines and concepts.', 'https://media.retroachievements.org/Images/120964.png', 'https://media.retroachievements.org/Images/040522.png', 'https://media.retroachievements.org/Images/014665.png', 'https://media.retroachievements.org/Images/014664.png', 4.3),
  (59, 5151, 'Harvest Moon GBC', 'Game Boy Color', 6, 605, 605, 605, 47, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '1998-12-31', 'Harvest Moon GB  is the second game in the Story of Seasons series of video games, and was developed and published by Victor Interactive Software. Harvest Moon GB is the first portable Harvest Moon game, developed for the Game Boy. A Game Boy Color version was released later under the name Harvest Moon GBC. The Game Boy Color version was later released on the 3DS Virtual Console in 2013.', 'https://media.retroachievements.org/Images/051639.png', 'https://media.retroachievements.org/Images/064743.png', 'https://media.retroachievements.org/Images/003473.png', 'https://media.retroachievements.org/Images/003479.png', 4.3),
  (60, 6494, 'Pocket Bomberman', 'Game Boy Color', 6, 595, 595, 595, 15, 0, 'Action', 'Hudson Soft', 'Nintendo', '1998-12-14', 'Pocket Bomberman is a platform video game developed by Hudson Soft and originally released for the Game Boy in 1997. It was re-released as a launch title for the Game Boy Color in 1998.', 'https://media.retroachievements.org/Images/044111.png', 'https://media.retroachievements.org/Images/007920.png', 'https://media.retroachievements.org/Images/009445.png', 'https://media.retroachievements.org/Images/007922.png', 4.3),
  (61, 6135, 'Beatmania GB', 'Game Boy Color', 6, 579, 579, 579, 70, 0, 'Rhythm', 'Konami', 'Konami', '1999-03-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/047951.png', 'https://media.retroachievements.org/Images/005053.png', 'https://media.retroachievements.org/Images/004990.png', 'https://media.retroachievements.org/Images/004991.png', 4.3),
  (62, 11149, 'Hello Kitty no Magical Museum', 'Game Boy Color', 6, 579, 579, 579, 9, 0, 'Puzzle', 'Atelier Double', 'Imagineer', '1999-04-28', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/053496.png', 'https://media.retroachievements.org/Images/053489.png', 'https://media.retroachievements.org/Images/053490.png', 'https://media.retroachievements.org/Images/053491.png', 4.3),
  (63, 6081, '~Hack~ Pokémon Pinball Generations', 'Game Boy Color', 6, 565, 565, 565, 67, 0, 'Pinball', 'RainbowDevs', NULL, '2019-01-19', 'Pokémon Red Version and Pokémon Blue Version are 1996 role-playing video games (RPGs) developed by Game Freak and published by Nintendo for the Game Boy. They are the first installments of the Pokémon video game series, and were first released in Japan as Pocket Monsters Red and Pocket Monsters Green, followed by the special edition Pocket Monsters Blue later that year. The games were released internationally in 1998 and 1999 as Pokémon Red and Pokémon Blue, while an enhanced version, Pokémon Yellow Version: Special Pikachu Edition, was released in Japan in 1998 and in other regions in 1999 and 2000.', 'https://media.retroachievements.org/Images/084083.png', 'https://media.retroachievements.org/Images/082931.png', 'https://media.retroachievements.org/Images/082936.png', 'https://media.retroachievements.org/Images/085959.png', 4.3),
  (64, 3819, 'John Romero''s Daikatana', 'Game Boy Color', 6, 548, 548, 548, 22, 0, 'Action-Adventure', 'Will', 'Kemco', '2000-09-29', 'John Romero''s Daikatana, better known as simply Daikatana, is a 2000 first-person shooter action role-playing game developed by Ion Storm and published by Eidos Interactive for Windows. A port to the Nintendo 64 was released the same year by Kemco. Players control a swordsmaster who travels through various time periods using the eponymous Daikatana, a powerful sword tied to the fate of the world.', 'https://media.retroachievements.org/Images/063217.png', 'https://media.retroachievements.org/Images/016042.png', 'https://media.retroachievements.org/Images/044897.png', 'https://media.retroachievements.org/Images/044893.png', 4.3),
  (65, 6080, 'Daffy Duck: Fowl Play', 'Game Boy Color', 6, 544, 544, 544, 24, 0, '2D Platforming', 'Santaclaus', 'Sunsoft', '1999-12-01', 'Daffy Duck: Fowl Play is a 2D platform video game featuring the Looney Tunes character Daffy Duck. It was released for the Game Boy Color in 1999 in North America and 2000 in Japan and Europe.', 'https://media.retroachievements.org/Images/042771.png', 'https://media.retroachievements.org/Images/011018.png', 'https://media.retroachievements.org/Images/033856.png', 'https://media.retroachievements.org/Images/033857.png', 4.3),
  (66, 13182, 'Top Gear Pocket 2', 'Game Boy Color', 6, 541, 541, 541, 86, 0, 'Racing', 'Vision Works', 'Vatical Entertainment', '2000-01-01', 'Top Gear Pocket 2, known in Europe as Top Gear Rally 2, is a racing video game developed by Kemco and released for the Game Boy Color handheld console, released on December 17, 1999 in Japan and in 2000 across other regions. It is a sequel to Top Gear Pocket.', 'https://media.retroachievements.org/Images/061109.png', 'https://media.retroachievements.org/Images/061106.png', 'https://media.retroachievements.org/Images/061107.png', 'https://media.retroachievements.org/Images/061108.png', 4.3),
  (67, 4193, 'Monsters, Inc.', 'Game Boy Color', 6, 534, 534, 534, 15, 0, '2D Platforming', 'Vicarious Visions', 'THQ', '2001-10-01', 'Monsters, Inc. is a 2001 American animated comedy film produced by Pixar Animation Studios for Walt Disney Pictures, and starring the voices of John Goodman, Billy Crystal, Steve Buscemi, James Coburn, Jennifer Tilly, and Mary Gibbs. Directed by Pete Docter, and written by Andrew Stanton and Daniel Gerson, the film centers on two monsters, the hairy James P. "Sulley" Sullivan (Goodman) and his one-eyed partner and best friend Mike Wazowski (Crystal), who are employed at the titular energy-producing factory Monsters, Inc., which generates power by scaring human children. However, the monster world believes that the children are toxic, and when a little human girl, Boo (Gibbs), sneaks into the factory, the duo must safely return her home while evading discovery.', 'https://media.retroachievements.org/Images/044845.png', 'https://media.retroachievements.org/Images/051581.png', 'https://media.retroachievements.org/Images/002203.png', 'https://media.retroachievements.org/Images/044397.png', 4.3),
  (68, 12950, 'Hollywood Pinball', 'Game Boy Color', 6, 515, 515, 515, 85, 0, 'Pinball', 'Tarantula Studios', 'Take-Two Interactive', '1999-01-01', 'Hollywood Pinball is a 1999 pinball video game developed by Tarantula Studios, first published by Take-Two Interactive Software in the EU for Game Boy Color in 1999. Hollywood Pinball was unreleased within the United States.', 'https://media.retroachievements.org/Images/063202.png', 'https://media.retroachievements.org/Images/018185.png', 'https://media.retroachievements.org/Images/018186.png', 'https://media.retroachievements.org/Images/018187.png', 4.3),
  (69, 15635, 'Super Robot Pinball', 'Game Boy Color', 6, 515, 515, 515, 44, 0, 'Pinball', NULL, 'Media Factory', '2001-02-23', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/065603.png', 'https://media.retroachievements.org/Images/064728.png', 'https://media.retroachievements.org/Images/030248.png', 'https://media.retroachievements.org/Images/030249.png', 4.3),
  (70, 4921, 'Asteroids', 'Game Boy Color', 6, 506, 506, 506, 34, 0, NULL, 'Syrox Developments', 'Activision', '1999-09-01', 'An asteroid is a minor planet—an object larger than a meteoroid that is neither a planet nor an identified comet—that orbits within the inner Solar System or is co-orbital with Jupiter. Asteroids are rocky, metallic, or icy bodies with no atmosphere, and are broadly classified into C-type (carbonaceous), M-type (metallic), or S-type (silicaceous). The size and shape of asteroids vary significantly, ranging from small rubble piles under a kilometer across to Ceres, a dwarf planet almost 1000 km in diameter. A body is classified as a comet, not an asteroid, if it shows a coma (tail) when warmed by solar radiation, although recent observations suggest a continuum between these types of bodies.', 'https://media.retroachievements.org/Images/025466.png', 'https://media.retroachievements.org/Images/067093.png', 'https://media.retroachievements.org/Images/025464.png', 'https://media.retroachievements.org/Images/025465.png', 4.3),
  (71, 5105, 'Dragon Quest Monsters 2', 'Game Boy Color', 6, 482, 482, 482, 61, 0, 'Turn-Based RPG', 'TOSE', 'Enix', '2001-03-09', 'Dragon Warrior Monsters 2, known in Japan as Dragon Quest Monsters 2 , is a role-playing video game published by Enix for the Game Boy Color. It is the second Dragon Warrior Monsters game for the Game Boy Color and features two different versions of the same game, Cobi''s Journey and Tara''s Adventure. Both games were remade in 2002 for the PlayStation in a compilation game called Dragon Quest Monsters 1+2 and released only in Japan. The Nintendo 3DS version combined both games into one and was released only in Japan in 2014 with the title Dragon Quest Monsters 2: Iru and Luca''s Marvelous Mysterious Key. The 3DS version was later brought to iOS, Android on August 6, 2020, in Japan.', 'https://media.retroachievements.org/Images/086569.png', 'https://media.retroachievements.org/Images/042483.png', 'https://media.retroachievements.org/Images/042479.png', 'https://media.retroachievements.org/Images/042480.png', 4.3),
  (72, 8571, 'Batman Beyond: Return of the Joker', 'Game Boy Color', 6, 479, 479, 479, 10, 0, 'Beat ''em Up', 'Kemco', 'Ubisoft', '2000-11-20', 'Batman Beyond: Return of the Joker is a 2000 American direct-to-video animated superhero film produced by Warner Bros. Animation and distributed by Warner Bros. Home Entertainment. It is the third film in the DC Animated Universe and is based on the animated series Batman Beyond while also serving as a continuation of and resolving plot points from Batman: The Animated Series and The New Batman Adventures. The film features the DC Comics Batmen Bruce Wayne and Terry McGinnis, as they try to unravel the mysterious return of the former''s archenemy, the Joker, preparing a climactic showdown with the villain.', 'https://media.retroachievements.org/Images/113443.png', 'https://media.retroachievements.org/Images/042666.png', 'https://media.retroachievements.org/Images/066977.png', 'https://media.retroachievements.org/Images/066978.png', 4.3),
  (73, 22124, '~Homebrew~ Blinky''s Revenge', 'Game Boy Color', 6, 461, 461, 461, 6, 0, 'Maze Chase', 'László Rajcsányi', 'László Rajcsányi', '2022-06-21', ' This is a list of fictional crocodiles and alligators from literature, mascots and emblems of teams and organizations, comics, films, animations and video games.', 'https://media.retroachievements.org/Images/118223.png', 'https://media.retroachievements.org/Images/106173.png', 'https://media.retroachievements.org/Images/106175.png', 'https://media.retroachievements.org/Images/106176.png', 4.3),
  (74, 5061, '102 Dalmatians: Puppies to the Rescue', 'Game Boy Color', 6, 455, 455, 455, 36, 0, '2D Platforming', 'Digital Eclipse', 'Activision', '2000-12-06', '102 Dalmatians: Puppies to the Rescue is a 2000 platform game, loosely based on the 2000 film 102 Dalmatians. It was developed by Toys for Bob and published by Eidos Interactive for PlayStation and Dreamcast while Disney Interactive published the Windows version. The Game Boy Color version was developed by Digital Eclipse and published by Activision.', 'https://media.retroachievements.org/Images/060696.png', 'https://media.retroachievements.org/Images/060800.png', 'https://media.retroachievements.org/Images/060799.png', 'https://media.retroachievements.org/Images/060815.png', 4.3),
  (75, 7109, 'Buffy the Vampire Slayer', 'Game Boy Color', 6, 447, 447, 447, 18, 0, NULL, 'GameBrains', NULL, '2000-09-19', 'Buffy the Vampire Slayer is an American supernatural horror drama television series created by Joss Whedon. The show''s concept is based on the 1992 film written by Whedon, although they are separate and distinct productions. Whedon served as executive producer and showrunner of the series under his production company Mutant Enemy Productions. It aired on The WB from March 10, 1997, to May 22, 2001, and later on UPN from October 2, 2001, to May 20, 2003.', 'https://media.retroachievements.org/Images/113126.png', 'https://media.retroachievements.org/Images/097212.png', 'https://media.retroachievements.org/Images/073439.png', 'https://media.retroachievements.org/Images/073438.png', 4.3),
  (76, 4647, 'Rayman 2', 'Game Boy Color', 6, 443, 443, 443, 54, 0, '2D Platforming', 'Ubisoft', 'Ubisoft', '2002-01-01', 'Rayman 2: The Great Escape is a 1999 platform game developed by Ubi Pictures and published by Ubi Soft for the Nintendo 64, Windows, Dreamcast and PlayStation. The game centers on the titular character Rayman, who is tasked with saving the fantastical land of the Fairy Glade from an army of robotic pirates led by Admiral Razorbeard.', 'https://media.retroachievements.org/Images/071847.png', 'https://media.retroachievements.org/Images/014328.png', 'https://media.retroachievements.org/Images/033881.png', 'https://media.retroachievements.org/Images/033869.png', 4.3),
  (77, 6524, 'Bionic Commando: Elite Forces', 'Game Boy Color', 6, 438, 438, 438, 49, 0, '2D Platforming, Metroidvania', 'Nintendo', 'Nintendo', '2000-01-01', 'Bionic Commando: Elite Forces is a 2000 platform video game developed by Nintendo Software Technology and published by Nintendo for the Game Boy Color. It is an installment of Capcom''s Bionic Commando series developed under license by Nintendo, and was the first title to be developed by its Redmond-based first-party studio Nintendo Software Technology. It is the sequel to the Game Boy version of Bionic Commando. It was not released in Europe until November 2014 when it was released for the Nintendo 3DS Virtual Console in Europe.', 'https://media.retroachievements.org/Images/019006.png', 'https://media.retroachievements.org/Images/095872.png', 'https://media.retroachievements.org/Images/019003.png', 'https://media.retroachievements.org/Images/019004.png', 4.3),
  (78, 2370, '~Prototype~ Resident Evil', 'Game Boy Color', 6, 429, 429, 429, 19, 0, 'Survival Horror', 'HotGen Studios', 'Capcom', NULL, 'Resident Evil, known as Biohazard  in Japan, is a Japanese horror game series and media franchise created by Capcom. It consists of survival horror, third-person shooter and first-person games, with players typically surviving in environments inhabited by zombies and other mutated creatures. The franchise has expanded into media including a live-action film series, animated films, television series, comic books, novels, audiobooks, and merchandise. Resident Evil is among the highest-grossing horror franchises of all time, and is Capcom''s best-selling franchise, with over 170 million copies sold worldwide as of March 2025. Individual installments of the series have been critically acclaimed and have received several awards, and many characters from the series such as Leon S. Kennedy and Albert Wesker have been described as video game icons.', 'https://media.retroachievements.org/Images/040116.png', 'https://media.retroachievements.org/Images/045393.png', 'https://media.retroachievements.org/Images/016487.png', 'https://media.retroachievements.org/Images/016486.png', 4.3),
  (79, 4950, 'Antz', 'Game Boy Color', 6, 418, 418, 418, 28, 0, '2D Platforming', 'CLCE & Planet', 'Infogrames', '1999-09-24', 'Antz is a 1998 American animated adventure comedy film directed by Eric Darnell and Tim Johnson, and written by Todd Alcott, Chris Weitz and Paul Weitz, with additional sequences directed by Lawrence Guterman. Produced by DreamWorks Animation and PDI, the film features an ensemble voice cast, including Woody Allen, Sharon Stone, Jennifer Lopez, Sylvester Stallone, Christopher Walken, Dan Aykroyd, Anne Bancroft, Danny Glover and Gene Hackman. Some of the main characters share facial similarities with the actors who voice them. The film involves an anxious worker ant, Z, who falls in love with Princess Bala. When the arrogant General Mandible attempts to seize control of the ant colony, Z must combine his desire for purpose with his inner strength to save everyone.', 'https://media.retroachievements.org/Images/048931.png', 'https://media.retroachievements.org/Images/007023.png', 'https://media.retroachievements.org/Images/007021.png', 'https://media.retroachievements.org/Images/007022.png', 4.3),
  (80, 12804, 'Meitantei Conan: Karakuri Jiin Satsujin Jiken', 'Game Boy Color', 6, 414, 414, 414, 12, 0, NULL, NULL, NULL, '2000-02-25', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/017556.png', 'https://media.retroachievements.org/Images/017150.png', 'https://media.retroachievements.org/Images/017148.png', 'https://media.retroachievements.org/Images/017149.png', 4.3),
  (81, 4671, 'The Powerpuff Girls: Bad Mojo Jojo', 'Game Boy Color', 6, 414, 414, 414, 42, 0, '2D Platforming', 'Sennari Interactive', 'BAM! Entertainment', '2000-11-14', 'The Powerpuff Girls: Bad Mojo Jojo is a 2000 platform game developed by Sennari Interactive and published by Bay Area Multimedia for the Game Boy Color. It is based on Cartoon Network animated series The Powerpuff Girls.', 'https://media.retroachievements.org/Images/088583.png', 'https://media.retroachievements.org/Images/022186.png', 'https://media.retroachievements.org/Images/002209.png', 'https://media.retroachievements.org/Images/022189.png', 4.3),
  (82, 7130, 'Dance Dance Revolution GB', 'Game Boy Color', 6, 408, 408, 408, 70, 0, 'Rhythm', 'Now Production', 'Konami', '2000-08-03', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/061325.png', 'https://media.retroachievements.org/Images/017858.png', 'https://media.retroachievements.org/Images/017856.png', 'https://media.retroachievements.org/Images/017857.png', 4.3),
  (83, 8630, 'BattleTanx', 'Game Boy Color', 6, 405, 405, 405, 32, 0, 'Vehicular Combat', 'The 3DO Company', 'Lucky Chicken Games', '2000-04-01', 'BattleTanx is a 1998 action game released for the Nintendo 64, produced by The 3DO Company. The game was followed by a 1999 sequel, titled BattleTanx: Global Assault.', 'https://media.retroachievements.org/Images/066987.png', 'https://media.retroachievements.org/Images/023845.png', 'https://media.retroachievements.org/Images/066990.png', 'https://media.retroachievements.org/Images/066991.png', 4.3),
  (84, 4192, 'Monkey Puncher', 'Game Boy Color', 6, 393, 393, 393, 33, 0, 'Management Simulation, Pet Simulation', 'Taito', 'Event Horizon Software', '2000-03-24', 'Monkey Puncher  is a video game for the Game Boy Color, developed by Atelier Double, and released in December 2000. The game''s goal is to train a monkey to fight in organised boxing matches in order to save the main character''s father and sibling.', 'https://media.retroachievements.org/Images/105118.png', 'https://media.retroachievements.org/Images/047647.png', 'https://media.retroachievements.org/Images/047645.png', 'https://media.retroachievements.org/Images/047646.png', 4.3),
  (85, 4922, 'Warlocked', 'Game Boy Color', 6, 389, 389, 389, 54, 0, 'Real-Time Strategy', 'Bits Studios', 'Nintendo', '2000-07-24', 'Warlocked is a real-time strategy video game developed by Bits Studios and published by Nintendo for the Game Boy Color. It was solely released in North America on July 24, 2000. Choosing between human and beast factions, the player plays through twelve scenarios from each faction, gathering resources, building fortresses, and managing troops to defeat the opposing force.', 'https://media.retroachievements.org/Images/002782.png', 'https://media.retroachievements.org/Images/002681.png', 'https://media.retroachievements.org/Images/002815.png', 'https://media.retroachievements.org/Images/002781.png', 4.3),
  (86, 24391, '~Homebrew~ Retro Quiz Tower: JAM Edition', 'Game Boy Color', 6, 376, 376, 376, 6, 0, NULL, 'Rubenretro', 'Rubenretro', '2023-05-20', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/112764.png', 'https://media.retroachievements.org/Images/073662.png', 'https://media.retroachievements.org/Images/112690.png', 'https://media.retroachievements.org/Images/112691.png', 4.2),
  (87, 16252, '~Hack~ Pokémon Fool''s Gold', 'Game Boy Color', 6, 374, 374, 374, 124, 0, 'Turn-Based RPG', 'Kingbigb0y, Froqpond, G.eeb', 'Hack - Pokemon Crystal Version', '2020-04-01', '2001 saw many sequels and prequels in video games, such as Madden NFL 2002, NBA Live 2002, NBA 2K2, WWF Smackdown! Just Bring It, Capcom vs. SNK 2, Crazy Taxi 2, Dead or Alive 3, Final Fantasy X, Gran Turismo 3: A-Spec, Grand Theft Auto III, Metal Gear Solid 2: Sons of Liberty, Myst III: Exile, Silent Hill 2, Sonic Adventure 2, SSX Tricky, Super Smash Bros. Melee, Tekken 4, Tony Hawk''s Pro Skater 3, and Virtua Fighter 4. New intellectual properties include Phoenix Wright: Ace Attorney, Advance Wars, Animal Crossing, Burnout, Gothic, Black & White, Devil May Cry, Fatal Frame, Ghost Recon, Halo: Combat Evolved, Jak and Daxter, Max Payne, Oni, Onimusha: Warlords, Operation Flashpoint, Pikmin, Pro Evolution Soccer, Red Faction, Serious Sam, and Tropico.', 'https://media.retroachievements.org/Images/090889.png', 'https://media.retroachievements.org/Images/034135.png', 'https://media.retroachievements.org/Images/034132.png', 'https://media.retroachievements.org/Images/034133.png', 4.2),
  (88, 5143, 'Harvest Moon 3 GBC', 'Game Boy Color', 6, 364, 364, 364, 57, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2000-09-29', 'Harvest Moon 3 GBC  is a farm simulation video game for the Game Boy Color developed and published by Victor Interactive Software, part of the long-running Story of Seasons series of video games. The game was released for the Nintendo 3DS via Virtual Console in North America on December 11, 2014.', 'https://media.retroachievements.org/Images/087833.png', 'https://media.retroachievements.org/Images/003441.png', 'https://media.retroachievements.org/Images/003436.png', 'https://media.retroachievements.org/Images/003440.png', 4.2),
  (89, 4080, 'Alfred''s Adventure', 'Game Boy Color', 6, 363, 363, 363, 33, 0, '2D Platforming', 'SCi Games | Sales Curve Interactive', 'Rockstar Games', '2000-09-01', 'Alfred Chicken is a platform video game developed by Twilight and published by Mindscape for the Game Boy. It was later ported to the Amiga, Amiga CD32, NES, and Super NES in 1993 and February 1994, in Europe and North America, respectively. A Europe-exclusive remake of the game, entitled Alfred''s Adventure, was developed by Möbius Entertainment and released by SCi for Game Boy Color in June 2000. Another remake, named Alfred Chicken, was also developed by King Monkey, a division of Möbius Entertainment, and released by Sony Computer Entertainment for PlayStation in 2002. Rockstar Games does not own the title''s rights, despite buying Möbius later on, as Jason McGann personally held the rights.', 'https://media.retroachievements.org/Images/049212.png', 'https://media.retroachievements.org/Images/005877.png', 'https://media.retroachievements.org/Images/005878.png', 'https://media.retroachievements.org/Images/044693.png', 4.2),
  (90, 18707, '~Homebrew~ ~Demo~ Mina the Hollower GBC Demake', 'Game Boy Color', 6, 362, 362, 362, 6, 0, 'Action-Adventure', 'Jan Klečka', 'Jan Klečka', '2022-02-25', NULL, 'https://media.retroachievements.org/Images/111710.png', 'https://media.retroachievements.org/Images/054307.png', 'https://media.retroachievements.org/Images/054305.png', 'https://media.retroachievements.org/Images/054306.png', 4.2),
  (91, 6136, 'Motocross Maniacs 2', 'Game Boy Color', 6, 360, 360, 360, 43, 0, 'Extreme Sports - Motocross', 'Konami Computer Entertainment Osaka', 'Konami', '1999-09-10', 'Motocross Maniacs 2 is a 1999 racing game for the Game Boy Color, developed and published by Konami. A sequel to the 1989 Game Boy title Motocross Maniacs, the game is a racing game in which the player drives across a side-scrolling motocross course.', 'https://media.retroachievements.org/Images/071375.png', 'https://media.retroachievements.org/Images/004993.png', 'https://media.retroachievements.org/Images/004994.png', 'https://media.retroachievements.org/Images/004995.png', 4.2),
  (92, 7638, 'Aladdin', 'Game Boy Color', 6, 353, 353, 353, 35, 0, '2D Platforming', 'Crawfish Interactive', ' Disney Interactive Studios, Ubisoft', '2000-11-07', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/096418.png', 'https://media.retroachievements.org/Images/094813.png', 'https://media.retroachievements.org/Images/091213.png', 'https://media.retroachievements.org/Images/091214.png', 4.2),
  (93, 10849, 'Buzz Lightyear of Star Command', 'Game Boy Color', 6, 349, 349, 349, 27, 0, 'Action / Racing', 'Traveller''s Tales', 'Activision', '2000-11-01', 'Buzz Lightyear of Star Command is an American animated science fiction comedy television series produced by Walt Disney Television Animation. It is a spin-off of Pixar''s Toy Story franchise. The series was preceded by the direct-to-video film Buzz Lightyear of Star Command: The Adventure Begins, and aired on ABC and UPN from October 2, 2000, to January 13, 2001. While the series is 2D animated, Pixar animated the CGI opening title sequence.', 'https://media.retroachievements.org/Images/114100.png', 'https://media.retroachievements.org/Images/014668.png', 'https://media.retroachievements.org/Images/014667.png', 'https://media.retroachievements.org/Images/014669.png', 4.2),
  (94, 33577, '~Homebrew~ Fable: 20th Anniversary Demake', 'Game Boy Color', 6, 339, 339, 339, 6, 0, 'Adventure', 'james222', 'james222', '2024-10-17', 'The Chocobo  is a fictional species created for the Final Fantasy franchise by Square Enix. A galliform bird commonly having yellow feathers, they were first introduced in Final Fantasy II (1988), and have since featured in some capacity in nearly every Final Fantasy title, usually as a means of transport. Chocobos or chocobo-themed characters have played story roles in multiple titles, notably in Final Fantasy V and XIII. A recurring Chocobo also acts as protagonist of the Chocobo spin-off series.', 'https://media.retroachievements.org/Images/111512.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/111513.png', 'https://media.retroachievements.org/Images/111514.png', 4.2),
  (95, 6536, 'Looney Tunes Collector: Alert!', 'Game Boy Color', 6, 326, 326, 326, 17, 0, 'Action-Adventure', 'Infogrames', 'Infogrames, Syscom', '2000-06-24', 'Looney Tunes Collector: Martian Alert! is a Looney Tunes game developed and published by Infogrames for the Game Boy Color in 2000.', 'https://media.retroachievements.org/Images/105174.png', 'https://media.retroachievements.org/Images/015136.png', 'https://media.retroachievements.org/Images/047946.png', 'https://media.retroachievements.org/Images/047947.png', 4.2),
  (96, 2502, 'Lufia: The Legend Returns', 'Game Boy Color', 6, 316, 316, 316, 59, 0, 'Turn-Based RPG', 'Neverland', 'Natsume', '2001-09-20', 'Lufia: The Legend Returns is a role-playing video game for the Game Boy Color developed by Neverland and published by Taito, Natsume Inc., and Ubi Soft in Japan, North America, and Europe, respectively, in 2001. It is the third game in the Lufia series and the first one to appear on a handheld gaming system.', 'https://media.retroachievements.org/Images/107710.png', 'https://media.retroachievements.org/Images/002671.png', 'https://media.retroachievements.org/Images/002670.png', 'https://media.retroachievements.org/Images/044410.png', 4.2),
  (97, 16218, 'The Smurfs'' Nightmare', 'Game Boy Color', 6, 315, 315, 315, 60, 0, '2D Platforming', 'Velez & Dubail', 'Infogrames', '1999-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/067943.png', 'https://media.retroachievements.org/Images/033113.png', 'https://media.retroachievements.org/Images/033109.png', 'https://media.retroachievements.org/Images/033111.png', 4.2),
  (98, 29687, '~Homebrew~ The Best Text Adventure', 'Game Boy Color', 6, 314, 314, 314, 9, 0, 'Text Adventure', 'Stephen Allen, Matte Trucks', 'Shining Kitten Games', '2023-01-01', 'Dragon Quest, titled Dragon Warrior when initially localized to North America, is a 1986 role-playing video game developed by Chunsoft and published by Enix for the Nintendo Entertainment System. It was originally released in Japan in May 1986 and by Nintendo in North America in August 1989. It is the first game in the Dragon Quest video game series. Dragon Quest has been ported and remade for several video game platforms. As of 2019, it has been ported to MSX, MSX2, PC-9801, Super Famicom, Game Boy Color, mobile phones, and Nintendo Switch. The player controls the hero character who is charged with saving the Kingdom of Alefgard and rescuing its princess from the evil Dragonlord. Dragon Warrior''s story became the second part in a trilogy, with several spinoff anime and manga series.', 'https://media.retroachievements.org/Images/095562.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/095563.png', 'https://media.retroachievements.org/Images/095564.png', 4.2),
  (99, 26399, 'Käpt''n Blaubär: Die verrückte Schatzsuche', 'Game Boy Color', 6, 313, 313, 313, 18, 0, NULL, 'Shin''en Multimedia', 'Ravensburger Interactive Media', '2001-01-10', 'Käpt''n Blaubär is a fictional character created by novelist and comic artist Walter Moers. He is an anthropomorphic talking bear with blue fur who originally appeared in the German children''s television program Die Sendung mit der Maus, has since then appeared in a film, a novel, a stage musical and various other media, all of which chronicle the character''s life as a sailor and adventurer. Outside of Germany, Captain Bluebear is best known for being the protagonist of Moers'' novel The 13½ Lives of Captain Bluebear.', 'https://media.retroachievements.org/Images/089479.png', 'https://media.retroachievements.org/Images/089470.png', 'https://media.retroachievements.org/Images/089477.png', 'https://media.retroachievements.org/Images/089478.png', 4.2),
  (100, 28796, '~Homebrew~ Days Without', 'Game Boy Color', 6, 308, 308, 308, 8, 0, 'Survival Horror', 'Elvies', 'Elvies', '2023-01-01', 'Overcome is the fourth studio album by the American heavy metal band All That Remains. It was released on September 16, 2008. Overcome is the first album with drummer Jason Costa.', 'https://media.retroachievements.org/Images/092886.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/090021.png', 'https://media.retroachievements.org/Images/090022.png', 4.2),
  (101, 4125, 'Metal Walker', 'Game Boy Color', 6, 303, 303, 303, 27, 0, NULL, 'Capcom', 'Capcom', '2001-02-06', 'Metal Walker, known as Bakusou Senki Metal Walker GB: Kotetsu no Yuujou  in Japan, is a role-playing video game for the Game Boy Color, developed and published by Capcom. Many critics likened the game to the Pokémon series, but praised the game''s unique qualities. In Japan, the game inspired merchandise based on the Metal Walker robots.', 'https://media.retroachievements.org/Images/066852.png', 'https://media.retroachievements.org/Images/019015.png', 'https://media.retroachievements.org/Images/019013.png', 'https://media.retroachievements.org/Images/019014.png', 4.2),
  (102, 4100, 'Azure Dreams', 'Game Boy Color', 6, 300, 300, 300, 55, 0, 'Roguelike', 'Konami', 'Konami', '1999-08-05', 'Azure Dreams is a roguelike role-playing video game developed by Konami Computer Entertainment Tokyo and published by Konami for the PlayStation. A Game Boy Color game with the same name was developed by Konami Computer Entertainment Nagoya and released two years later. A spiritual sequel, Tao''s Adventure: Curse of the Demon Seal, was released on the Nintendo DS in 2005.', 'https://media.retroachievements.org/Images/066585.png', 'https://media.retroachievements.org/Images/066067.png', 'https://media.retroachievements.org/Images/002667.png', 'https://media.retroachievements.org/Images/006626.png', 4.2),
  (103, 29578, 'Trip World DX', 'Game Boy Color', 6, 300, 300, 300, 35, 0, '2D Platforming', 'Limited Run Games, Sunsoft', 'Limited Run Games', '2023-11-30', 'Trip World is a 1992 platform game developed and published by Sunsoft for the Game Boy. It was released in Japan in 1992. The game''s plot centers around the bunny-like being Yakopoo and his quest to retrieve the flower of peace so that peace will return to his disarranged world. The protagonist''s trademark ability is to shapeshift into different forms.', 'https://media.retroachievements.org/Images/109251.png', 'https://media.retroachievements.org/Images/094952.png', 'https://media.retroachievements.org/Images/094951.png', 'https://media.retroachievements.org/Images/094950.png', 4.2),
  (104, 29790, '~Homebrew~ My Saturday Grounded', 'Game Boy Color', 6, 292, 292, 292, 6, 0, 'Adventure', 'Tustin2121', 'itch.io', '2021-09-28', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/098028.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/096803.png', 'https://media.retroachievements.org/Images/096804.png', 4.2),
  (105, 8926, '~Unlicensed~ Terrifying 911', 'Game Boy Color', 6, 292, 292, 292, 29, 0, 'Run & Gun', 'Hitek', 'Hitek / Li Cheng', '2002-01-01', 'Terrifier is a 2016 American independent slasher film written, edited, co-produced, and directed by Damien Leone. The film stars Jenna Kanell, Samantha Scaffidi, Catherine Corcoran, and David Howard Thornton. The plot centers on partygoer Tara Heyes (Kanell) and her sister Victoria (Scaffidi), who become targets of the enigmatic serial killer known only as Art the Clown (Thornton) on Halloween night.', 'https://media.retroachievements.org/Images/063338.png', 'https://media.retroachievements.org/Images/053108.png', 'https://media.retroachievements.org/Images/062834.png', 'https://media.retroachievements.org/Images/049859.png', 4.2),
  (106, 17429, '~Hack~ Pokémon Gold 97: Reforged | Pokémon Silver 97: Reforged', 'Game Boy Color', 6, 280, 280, 280, 28, 0, 'Turn-Based RPG', 'SourApple', 'Hack - Pokemon Crystal Version', '2020-12-29', '  This is a list of video game remakes and remasters and includes remakes as well as remasters of video games. It does not include clones and enhanced ports.', 'https://media.retroachievements.org/Images/066027.png', 'https://media.retroachievements.org/Images/051337.png', 'https://media.retroachievements.org/Images/041775.png', 'https://media.retroachievements.org/Images/041776.png', 4.2),
  (107, 6342, 'NSYNC: Get to the Show', 'Game Boy Color', 6, 280, 280, 280, 16, 0, 'Minigames', 'Stunt Puppy Entertainment', 'Infogrames', '2001-12-13', 'NSYNC was an American vocal group and pop boy band formed by Chris Kirkpatrick in Orlando, Florida, in 1995 and launched in Germany by BMG Ariola Munich. The group consisted of Kirkpatrick, JC Chasez, Joey Fatone, Justin Timberlake, and Jason Galasso who soon left and was replaced by Lance Bass. Their debut album NSYNC was successfully released to European countries in 1997 and later entered the American market with the single "I Want You Back".', 'https://media.retroachievements.org/Images/054927.png', 'https://media.retroachievements.org/Images/054953.png', 'https://media.retroachievements.org/Images/037619.png', 'https://media.retroachievements.org/Images/037620.png', 4.2),
  (108, 3632, 'Dexter''s Laboratory: Robot Rampage', 'Game Boy Color', 6, 276, 276, 276, 26, 0, 'Action', 'Altron', 'Bay Area Multimedia', '2000-11-14', 'Dexter''s Laboratory: Robot Rampage is an action video game published by Bay Area Multimedia for the Game Boy Color and released in the United States on November 28, 2000. It is a graphically redesigned version of the game Elevator Action EX, also developed by Altron, with characters from the American animated television series Dexter''s Laboratory from Cartoon Network.', 'https://media.retroachievements.org/Images/062617.png', 'https://media.retroachievements.org/Images/034276.png', 'https://media.retroachievements.org/Images/034278.png', 'https://media.retroachievements.org/Images/034277.png', 4.2),
  (109, 4702, 'Die Original Moorhuhnjagd', 'Game Boy Color', 6, 276, 276, 276, 12, 0, 'Gallery Shooter', 'Witan Entertainment BV', 'Ravensburger', '2000-11-08', 'Crazy Chicken, sometimes known as Chicken Hunter or Moorhen, is a shooting gallery video game franchise. While originally intended to merely serve as a small-scale advertising game, the first game''s unintended online release and subsequent distribution as shareware were followed by an unprecedented surge in popularity, making it Germany''s most popular computer game in the early 2000s and enabling Crazy Chicken to develop into a multi-platform franchise with a variety of spin-offs and merchandise.', 'https://media.retroachievements.org/Images/072537.png', 'https://media.retroachievements.org/Images/021695.png', 'https://media.retroachievements.org/Images/021696.png', 'https://media.retroachievements.org/Images/021711.png', 4.2),
  (110, 29774, '~Homebrew~ Borbo''s Quest', 'Game Boy Color', 6, 272, 272, 272, 9, 0, 'Adventure', 'FrogSoft', 'FrogSoft', '2020-12-20', NULL, 'https://media.retroachievements.org/Images/096605.png', 'https://media.retroachievements.org/Images/096606.png', 'https://media.retroachievements.org/Images/096594.png', 'https://media.retroachievements.org/Images/096597.png', 4.2),
  (111, 8497, 'Mortal Kombat 4', 'Game Boy Color', 6, 272, 272, 272, 26, 0, '2D Fighting', 'Digital Eclipse', 'Midway', '1998-12-12', 'Mortal Kombat 4 is a 1997 fighting game developed and published by Midway for arcades. It is the fourth main installment in the Mortal Kombat franchise, and a sequel to 1995''s Mortal Kombat 3. It is also the first title in the series to use 3D computer graphics, as well as the last in the series to have an arcade release. The game was ported to the PlayStation, Nintendo 64, Microsoft Windows, and Game Boy Color in 1998, followed by an updated version, titled Mortal Kombat Gold, for the Dreamcast in 1999.', 'https://media.retroachievements.org/Images/123572.png', 'https://media.retroachievements.org/Images/060737.png', 'https://media.retroachievements.org/Images/033877.png', 'https://media.retroachievements.org/Images/033873.png', 4.2),
  (112, 5155, 'Harvest Moon 2 GBC', 'Game Boy Color', 6, 260, 260, 260, 53, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '1999-08-16', 'Harvest Moon 2 GBC, released in Japan as Bokujō Monogatari GB2 (牧場物語GB2), is a farming simulation video game for the Game Boy Color developed and published by Victor Interactive Software, and the second portable game in the Story of Seasons series. The object of the game is to cultivate a farm to prevent the land from being used to build an amusement park. As with the previous game, the player may choose to play as a boy or a girl.', 'https://media.retroachievements.org/Images/059691.png', 'https://media.retroachievements.org/Images/003481.png', 'https://media.retroachievements.org/Images/003480.png', 'https://media.retroachievements.org/Images/003483.png', 4.2),
  (113, 686, 'Bugs Bunny: Crazy Castle 3', 'Game Boy Color', 6, 256, 256, 256, 16, 0, NULL, 'Kemco', 'Nintendo', '1999-01-29', 'Bugs Bunny: Crazy Castle 3  is a platform game developed by Kemco as part of the Crazy Castle series. It was originally released in Japan as a Game Boy title in July 1997 called Soreyuke!! Kid: Go! Go! Kid  starring the character Kid Klown. The title was later remade on the Game Boy Color to include colorized graphics and characters from the Looney Tunes series, which was released in Japan in January 1999 by Kemco, and later that year in North America and Europe by Nintendo. It replaces Honey Bunny with Lola Bunny as Bugs'' love interest to be rescued. It was followed by a sequel, Bugs Bunny in Crazy Castle 4, in 2000.', 'https://media.retroachievements.org/Images/054345.png', 'https://media.retroachievements.org/Images/005227.png', 'https://media.retroachievements.org/Images/005230.png', 'https://media.retroachievements.org/Images/005231.png', 4.2),
  (114, 12951, 'Nicktoons Racing', 'Game Boy Color', 6, 256, 256, 256, 29, 0, 'Kart Racing', 'Pipe Dream Interactive', 'Hasbro Interactive', '2000-12-07', 'Nicktoons Racing is a racing video game developed by Software Creations for the PlayStation and Microsoft Windows. An abridged version was developed by Pipe Dream for the Game Boy Color in 2000, while Crawfish Interactive developed another abridged version for the Game Boy Advance in 2002. An arcade version developed by Chicago Gaming was released in 2003.', 'https://media.retroachievements.org/Images/116383.png', 'https://media.retroachievements.org/Images/040661.png', 'https://media.retroachievements.org/Images/040631.png', 'https://media.retroachievements.org/Images/040632.png', 4.2),
  (115, 6167, 'Pop''n Music GB', 'Game Boy Color', 6, 256, 256, 256, 123, 0, 'Rhythm', 'Konami', 'Konami', '2000-03-30', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/061000.png', 'https://media.retroachievements.org/Images/005061.png', 'https://media.retroachievements.org/Images/005060.png', 'https://media.retroachievements.org/Images/005077.png', 4.2),
  (116, 3650, 'Mr. Nutz', 'Game Boy Color', 6, 253, 253, 253, 13, 0, '2D Platforming', 'Planet Interactive', 'Infogrames', '1999-11-01', 'Mr. Nutz (ミスターナッツ) is a 2D side-scrolling platform game published by Ocean Software. It was released for the Super Nintendo Entertainment System in late 1993 in Europe and in North America and Japan in 1994. In 1994, it was released for the Mega Drive as Ocean''s first Sega game, and on the Game Boy. It was also released on the Sega Channel in 1995, the Game Boy Color in 1999, and remade for the Game Boy Advance in 2001.', 'https://media.retroachievements.org/Images/043241.png', 'https://media.retroachievements.org/Images/017512.png', 'https://media.retroachievements.org/Images/043942.png', 'https://media.retroachievements.org/Images/043943.png', 4.2),
  (117, 6531, 'The Flintstones: Burgertime in Bedrock', 'Game Boy Color', 6, 250, 250, 250, 27, 0, NULL, 'Conspiracy Entertainment', 'Swing! Entertainment, Classified Games', '2000-12-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/031111.png', 'https://media.retroachievements.org/Images/031108.png', 'https://media.retroachievements.org/Images/031106.png', 'https://media.retroachievements.org/Images/031107.png', 4.2),
  (118, 31934, '~Homebrew~ Combo Fishing', 'Game Boy Color', 6, 248, 248, 248, 26, 0, 'Sports - Fishing', 'WilbosWorld', 'WilbosWorld', '2024-11-01', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/105177.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/104981.png', 'https://media.retroachievements.org/Images/104982.png', 4.2),
  (119, 4731, 'Magi Nation', 'Game Boy Color', 6, 246, 246, 246, 66, 0, NULL, 'Interactive Imagination', 'Interactive Imagination', '2001-01-01', 'Magi Nation is a 2001 video game for the Game Boy Color developed by American studio Interactive Imagination. It is based on the collectible card game Magi-Nation Duel.', 'https://media.retroachievements.org/Images/097866.png', 'https://media.retroachievements.org/Images/002673.png', 'https://media.retroachievements.org/Images/002672.png', 'https://media.retroachievements.org/Images/019007.png', 4.2),
  (120, 3625, 'M&M''s Minis Madness', 'Game Boy Color', 6, 243, 243, 243, 12, 0, '2D Platforming', 'Pipe Dream Interactive', 'Majesco Entertainment', '2000-12-08', ' This is a list of video games related to the M&M''s brand.', 'https://media.retroachievements.org/Images/106415.png', 'https://media.retroachievements.org/Images/019919.png', 'https://media.retroachievements.org/Images/044694.png', 'https://media.retroachievements.org/Images/044695.png', 4.2),
  (121, 2500, 'Oddworld Adventures II', 'Game Boy Color', 6, 243, 243, 243, 55, 0, 'Cinematic Platforming', 'Saffire', 'Atari', '2000-01-19', 'Oddworld: Abe''s Exoddus is a platform video game developed by Oddworld Inhabitants and published by GT Interactive. Although the game is a sequel to the video game Oddworld: Abe''s Oddysee, it is considered a spin-off title in the Oddworld series, and not part of the Oddworld Quintology. It was released in November 1998 for the PlayStation video game console and in December 1998 for Microsoft Windows. A Game Boy Color version, titled Oddworld Adventures 2, was released in 2000. The PlayStation version was re-released on the PlayStation Network in October 2009.', 'https://media.retroachievements.org/Images/018752.png', 'https://media.retroachievements.org/Images/008100.png', 'https://media.retroachievements.org/Images/018751.png', 'https://media.retroachievements.org/Images/018750.png', 4.2),
  (122, 14166, 'LEGO Island 2: The Brickster''s Revenge', 'Game Boy Color', 6, 239, 239, 239, 13, 0, 'Action-Adventure', 'Crawfish Interactive', 'LEGO Interactive | LEGO Media', '2001-03-30', 'Lego Island 2: The Brickster''s Revenge is a 2001 action-adventure video game developed by Silicon Dreams Studio and published by Lego Software. It is the sequel to Lego Island and was followed by Island Xtreme Stunts.', 'https://media.retroachievements.org/Images/041476.png', 'https://media.retroachievements.org/Images/026308.png', 'https://media.retroachievements.org/Images/026316.png', 'https://media.retroachievements.org/Images/026307.png', 4.2),
  (123, 4919, 'Quest: Brian''s Journey', 'Game Boy Color', 6, 239, 239, 239, 24, 0, 'Turn-Based RPG', 'Atelier Double', 'Sunsoft, Imagineer', '2000-01-15', 'Quest: Brian''s Journey is a 2000 role-playing video game published in North America by Sunsoft for the Game Boy Color. The game''s title screen instead displays the title as Quest RPG: Brian''s Journey.', 'https://media.retroachievements.org/Images/053956.png', 'https://media.retroachievements.org/Images/050758.png', 'https://media.retroachievements.org/Images/002638.png', 'https://media.retroachievements.org/Images/002821.png', 4.2),
  (124, 18594, 'Dancing Furby', 'Game Boy Color', 6, 238, 238, 238, 25, 0, 'Rhythm', 'TOSE', 'Tomy', '1999-12-24', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/053428.png', 'https://media.retroachievements.org/Images/053424.png', 'https://media.retroachievements.org/Images/053425.png', 'https://media.retroachievements.org/Images/053427.png', 4.2),
  (125, 14356, 'Tony Hawk''s Pro Skater', 'Game Boy Color', 6, 234, 234, 234, 12, 0, 'Extreme Sports - Skateboarding', 'Natsume', 'Activision', '2000-01-01', 'Tony Hawk''s Pro Skater, released as Tony Hawk''s Skateboarding in the United Kingdom, Australia, New Zealand, and parts of Europe, is a 1999 skateboarding video game developed by Neversoft and published by Activision. It is the first installment in the Tony Hawk''s series. It was released for the PlayStation on September 29, 1999 and was later ported to the Nintendo 64, Game Boy Color, Dreamcast, and N-Gage.', 'https://media.retroachievements.org/Images/041161.png', 'https://media.retroachievements.org/Images/041162.png', 'https://media.retroachievements.org/Images/041159.png', 'https://media.retroachievements.org/Images/041160.png', 4.2),
  (126, 25072, '~Hack~ Pokémon TCG Neo', 'Game Boy Color', 6, 232, 232, 232, 23, 0, 'Collectible Card Game', 'Cataclyptic', NULL, '2023-01-15', 'This is a list of video games with mechanics based on collectible card games. It includes games which directly simulate collectible card games, arcade games integrated with physical collectible card games, and video games in other genres which utilize elements of deck-building or card battling as a significant portion of their game mechanics. It does not include games which only feature card collecting or card battling as a minigame, nor does it include games which simulate traditional card games such as solitaire or poker.', 'https://media.retroachievements.org/Images/078094.png', 'https://media.retroachievements.org/Images/122432.png', 'https://media.retroachievements.org/Images/078172.png', 'https://media.retroachievements.org/Images/078173.png', 4.2),
  (127, 16089, 'Medarot 3: Kabuto Version', 'Game Boy Color', 6, 232, 232, 232, 149, 0, NULL, NULL, 'Imagineer', '2000-07-23', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/106988.png', 'https://media.retroachievements.org/Images/106979.png', 'https://media.retroachievements.org/Images/107439.png', 'https://media.retroachievements.org/Images/108517.png', 4.2),
  (128, 20036, '~Homebrew~ Postie', 'Game Boy Color', 6, 229, 229, 229, 6, 0, '2D Platforming', 'invertedHat', 'invertedHat', '2022-05-29', 'Postie, formerly Postie Plus, is a New Zealand clothing store chain. It was founded in 1909 by Thomas Dellaca. As of October 2022, Postie has 61 stores as well as an online platform. Together with Australian retailer Best & Less, it forms the Best & Less Group.', 'https://media.retroachievements.org/Images/059539.png', 'https://media.retroachievements.org/Images/059542.png', 'https://media.retroachievements.org/Images/059540.png', 'https://media.retroachievements.org/Images/059541.png', 4.2),
  (129, 6181, 'Dance Dance Revolution GB: Disney Mix', 'Game Boy Color', 6, 226, 226, 226, 61, 0, 'Rhythm', 'Now Production', 'Konami', '2001-03-29', 'Below is a list of video games based on Walt Disney Animation Studios shorts and features.', 'https://media.retroachievements.org/Images/057759.png', 'https://media.retroachievements.org/Images/017878.png', 'https://media.retroachievements.org/Images/017876.png', 'https://media.retroachievements.org/Images/017877.png', 4.1),
  (130, 30935, '~Homebrew~ Noble Blood', 'Game Boy Color', 6, 225, 225, 225, 8, 0, NULL, 'Conan', 'Conan', '2023-10-24', 'Dragon Quest, titled Dragon Warrior when initially localized to North America, is a 1986 role-playing video game developed by Chunsoft and published by Enix for the Nintendo Entertainment System. It was originally released in Japan in May 1986 and by Nintendo in North America in August 1989. It is the first game in the Dragon Quest video game series. Dragon Quest has been ported and remade for several video game platforms. As of 2019, it has been ported to MSX, MSX2, PC-9801, Super Famicom, Game Boy Color, mobile phones, and Nintendo Switch. The player controls the hero character who is charged with saving the Kingdom of Alefgard and rescuing its princess from the evil Dragonlord. Dragon Warrior''s story became the second part in a trilogy, with several spinoff anime and manga series.', 'https://media.retroachievements.org/Images/102468.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/102466.png', 'https://media.retroachievements.org/Images/102467.png', 4.1),
  (131, 12842, 'Dance Dance Revolution GB2', 'Game Boy Color', 6, 225, 225, 225, 71, 0, 'Rhythm', 'Now Production', 'Konami', '2000-11-16', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/061326.png', 'https://media.retroachievements.org/Images/017870.png', 'https://media.retroachievements.org/Images/017864.png', 'https://media.retroachievements.org/Images/017868.png', 4.1),
  (132, 28238, '~Homebrew~ The Mist', 'Game Boy Color', 6, 223, 223, 223, 12, 0, NULL, 'Yliader', 'itch.io', '2022-04-13', 'The Mist is a science fiction psychological horror cosmic horror novella by American author Stephen King. Originally written in the summer of 1976, the story was first published by Viking Press in 1980 as part of the Dark Forces anthology, an edited version was subsequently included in King''s 1985 collection Skeleton Crew.', 'https://media.retroachievements.org/Images/092887.png', 'https://media.retroachievements.org/Images/093741.png', 'https://media.retroachievements.org/Images/087800.png', 'https://media.retroachievements.org/Images/087797.png', 4.1),
  (133, 13082, 'Moorhen 3: ... The Chicken Chase!', 'Game Boy Color', 6, 221, 221, 221, 16, 0, 'Gallery Shooter', 'Sproing, Similis', 'Ubisoft', '2002-07-11', 'Crazy Chicken, sometimes known as Chicken Hunter or Moorhen, is a shooting gallery video game franchise. While originally intended to merely serve as a small-scale advertising game, the first game''s unintended online release and subsequent distribution as shareware were followed by an unprecedented surge in popularity, making it Germany''s most popular computer game in the early 2000s and enabling Crazy Chicken to develop into a multi-platform franchise with a variety of spin-offs and merchandise.', 'https://media.retroachievements.org/Images/036397.png', 'https://media.retroachievements.org/Images/036399.png', 'https://media.retroachievements.org/Images/036435.png', 'https://media.retroachievements.org/Images/036436.png', 4.1),
  (134, 6171, 'Beatmania GB2: GotchaMix', 'Game Boy Color', 6, 217, 217, 217, 95, 0, 'Rhythm', 'Konami', 'Konami', '1999-11-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/054090.png', 'https://media.retroachievements.org/Images/005054.png', 'https://media.retroachievements.org/Images/005055.png', 'https://media.retroachievements.org/Images/005057.png', 4.1),
  (135, 4246, 'Qix Adventure', 'Game Boy Color', 6, 214, 214, 214, 42, 0, 'Action-Puzzle', 'Coconuts Japan Entertainment', 'Taito', '1999-10-22', 'Qix Adventure is a 1999 video game developed by Coconuts Japan Entertainment and published by Taito for the Game Boy Color. An English port of the game was developed by Evolution Entertainment for the United Kingdom in 2000. The game is a puzzle game based on the 1981 Taito title Qix, with additional story elements.', 'https://media.retroachievements.org/Images/067630.png', 'https://media.retroachievements.org/Images/017649.png', 'https://media.retroachievements.org/Images/017646.png', 'https://media.retroachievements.org/Images/017650.png', 4.1),
  (136, 11582, 'Dance Dance Revolution GB3', 'Game Boy Color', 6, 212, 212, 212, 81, 0, 'Rhythm', 'Now Production', 'Konami', '2001-03-15', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/061327.png', 'https://media.retroachievements.org/Images/017873.png', 'https://media.retroachievements.org/Images/017872.png', 'https://media.retroachievements.org/Images/017874.png', 4.1),
  (137, 3637, 'Samurai Kid', 'Game Boy Color', 6, 212, 212, 212, 58, 0, NULL, 'Biox', 'Koei | Tecmo', '2001-02-02', 'Fujimaru of the Wind: The Childhood of a Ninja , also known as Samurai Kid, is a Japanese anime series produced by Toei Animation. 65 episodes aired from 7 June 1964 until 31 August 1965. It tells the story of a ninja''s pupil that controlled the wind.', 'https://media.retroachievements.org/Images/049333.png', 'https://media.retroachievements.org/Images/051023.png', 'https://media.retroachievements.org/Images/049334.png', 'https://media.retroachievements.org/Images/049335.png', 4.1),
  (138, 24117, '~Homebrew~ TUNIC', 'Game Boy Color', 6, 210, 210, 210, 10, 0, 'Action-Adventure', 'MintFerret', 'itch.io', '2023-01-20', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/072016.png', 'https://media.retroachievements.org/Images/071987.png', 'https://media.retroachievements.org/Images/071997.png', 'https://media.retroachievements.org/Images/071988.png', 4.1),
  (139, 8228, '~Unlicensed~ Zook Hero Z', 'Game Boy Color', 6, 209, 209, 209, 41, 0, '2D Platforming', 'Vast Fame', 'Li Cheng', '1999-01-01', 'Numerous notable people have had some form of mood disorder. This is a list of people accompanied by verifiable sources associating them with some form of bipolar disorder, including cyclothymia, based on their own public statements; this discussion is sometimes tied to the larger topic of creativity and mental illness. In the case of dead people only, individuals with a speculative or retrospective diagnosis should only be listed if they are accompanied by a source reflective of the mainstream, academic view. Individuals should not be added to this list unless the disorder is regularly and commonly mentioned in mainstream, reliable sources.', 'https://media.retroachievements.org/Images/050272.png', 'https://media.retroachievements.org/Images/008404.png', 'https://media.retroachievements.org/Images/107127.png', 'https://media.retroachievements.org/Images/107128.png', 4.1),
  (140, 4097, 'Alice in Wonderland', 'Game Boy Color', 6, 209, 209, 209, 45, 0, '2D Platforming', 'Digital Eclipse', 'Disney Interactive Studios', '2000-10-04', 'Alice''s Adventures in Wonderland is an 1865 English children''s novel by Lewis Carroll, a mathematics don at the University of Oxford. It details the story of a girl named Alice who falls through a rabbit hole into a fantasy world of anthropomorphic creatures. It is seen as an example of the literary nonsense genre. The artist John Tenniel provided 42 wood-engraved illustrations for the book.', 'https://media.retroachievements.org/Images/069065.png', 'https://media.retroachievements.org/Images/023822.png', 'https://media.retroachievements.org/Images/023826.png', 'https://media.retroachievements.org/Images/023827.png', 4.1),
  (141, 25233, 'Space Invaders', 'Game Boy Color', 6, 207, 207, 207, 24, 0, 'Shoot ''em Up', 'Crawfish Interactive', 'Activision', '1999-10-27', 'Space Invaders is a 1978 shoot ''em up video game developed and published by Taito for arcades. It was released in Japan in April 1978, and released overseas by Midway Manufacturing later that year. Space Invaders was the first video game with endless gameplay and the first fixed shooter, setting the template for the genre. The goal is to defeat waves of descending aliens with a horizontally moving laser cannon to earn as many points as possible.', 'https://media.retroachievements.org/Images/078387.png', 'https://media.retroachievements.org/Images/078384.png', 'https://media.retroachievements.org/Images/078385.png', 'https://media.retroachievements.org/Images/078386.png', 4.1),
  (142, 4190, 'Driver: You Are The Wheelman', 'Game Boy Color', 6, 204, 204, 204, 41, 0, 'Action, Arcade Racing', 'Crawfish Interactive', 'Infogrames', '2000-05-16', 'Driver is an action driving video game and the first installment in the Driver series. Developed by Reflections Interactive and published by GT Interactive, it was released on the PlayStation on 25 June 1999, and was ported to Microsoft Windows on 1 October 1999, and to Classic Mac OS on 12 December 2000 by Abersoft Limited.', 'https://media.retroachievements.org/Images/103085.png', 'https://media.retroachievements.org/Images/102603.png', 'https://media.retroachievements.org/Images/102601.png', 'https://media.retroachievements.org/Images/102600.png', 4.1),
  (143, 25708, '~Homebrew~ Feed IT Souls', 'Game Boy Color', 6, 202, 202, 202, 20, 0, '2D Platforming', 'Gumpy Function', 'itch.io', '2023-09-11', 'Kobe Bean Bryant was an American professional basketball player. A shooting guard, he spent his entire 20-year career with the Los Angeles Lakers in the National Basketball Association (NBA). Widely regarded as one of the greatest and most influential players in the sport''s history, Bryant won five NBA championships and was an 18-time All-Star, four-time All-Star MVP, 15-time member of the All-NBA Team, 12-time member of the All-Defensive Team, the 2008 NBA Most Valuable Player (MVP), two-time NBA Finals MVP, and two-time scoring champion. He ranks fourth in league all-time regular season and postseason scoring. Bryant was posthumously named to the NBA 75th Anniversary Team in 2021 and was a two-time inductee to the Naismith Memorial Basketball Hall of Fame, as a player in 2020 and as a member of the 2008 U.S. Olympic team in 2025.', 'https://media.retroachievements.org/Images/082360.png', 'https://media.retroachievements.org/Images/085169.png', 'https://media.retroachievements.org/Images/082358.png', 'https://media.retroachievements.org/Images/082359.png', 4.1),
  (144, 11206, 'Barbie: Pet Rescue', 'Game Boy Color', 6, 202, 202, 202, 22, 0, NULL, 'HotGen Studios', NULL, '2001-09-01', 'Barbie, a fashion doll manufactured by American toy and entertainment company Mattel, has starred in numerous video games on PC, various console systems, IOS, and Android. Some games are adaptations of Barbie films or TV series, while others feature original storylines and concepts.', 'https://media.retroachievements.org/Images/120984.png', 'https://media.retroachievements.org/Images/076154.png', 'https://media.retroachievements.org/Images/076152.png', 'https://media.retroachievements.org/Images/076153.png', 4.1),
  (145, 13091, 'Ballistic', 'Game Boy Color', 6, 198, 198, 198, 15, 0, NULL, 'Mitchell', 'Infogrames', '1999-01-01', 'Puzz Loop is an arcade tile-matching puzzle game developed by Mitchell Corporation and released in 1998 in Japan and North America and 1999 in Europe. It was later ported to the Game Boy Color, PlayStation and Samsung Nuon DVD players under the name Ballistic. The original Puzz Loop game was also known by this title. In 2008, publisher Hudson Soft released the game on App Store for the iPhone and iPod Touch. There was a Neo Geo Pocket Color version of the game initially planned to be published by SNK, but cancelled due to bankruptcy of the original incarnation of the company.', 'https://media.retroachievements.org/Images/110176.png', 'https://media.retroachievements.org/Images/019453.png', 'https://media.retroachievements.org/Images/110174.png', 'https://media.retroachievements.org/Images/110175.png', 4.1),
  (146, 6169, 'Pop ''n Music GB: Animation Melody', 'Game Boy Color', 6, 198, 198, 198, 96, 0, 'Rhythm', 'Konami', 'Konami', '2000-07-09', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/072267.png', 'https://media.retroachievements.org/Images/005083.png', 'https://media.retroachievements.org/Images/005082.png', 'https://media.retroachievements.org/Images/009531.png', 4.1),
  (147, 7708, 'Legend of the River King 2', 'Game Boy Color', 6, 197, 197, 197, 76, 0, 'Sports - Fishing', 'Marvelous Interactive', 'Natsume', '2001-04-17', 'River King or Harvest Fishing (PAL), and originally released in English as Legend of the River King, is a fishing-themed role playing video game series by Marvelous. The series has releases over 6 video game systems. Of these, 4 have been released in America.', 'https://media.retroachievements.org/Images/081097.png', 'https://media.retroachievements.org/Images/008019.png', 'https://media.retroachievements.org/Images/008018.png', 'https://media.retroachievements.org/Images/008020.png', 4.1),
  (148, 7304, 'Magical Tetris Challenge', 'Game Boy Color', 6, 195, 195, 195, 18, 0, NULL, 'Capcom', 'Capcom', '1999-11-12', 'Magical Tetris Challenge is a 1998 puzzle video game developed and published by Capcom for arcades. It was ported to the Nintendo 64, Game Boy Color and PlayStation. It is a version of Tetris featuring Disney characters. It is one of the few Nintendo 64 games to be entirely in 2D, in addition to being Capcom''s first game for the console. The Japanese arcade cabinet and cover art was done by Kenichi Sudo, while the North American cover art was done by Robert Griggs.', 'https://media.retroachievements.org/Images/041043.png', 'https://media.retroachievements.org/Images/007185.png', 'https://media.retroachievements.org/Images/007183.png', 'https://media.retroachievements.org/Images/007184.png', 4.1),
  (149, 6337, 'Robopon: Sun Version', 'Game Boy Color', 6, 193, 193, 193, 22, 0, 'Turn-Based RPG', 'Hudson Soft, Red', 'Hudson Soft, Atlus', '1998-12-04', 'Robopon Sun, Star and Moon Versions are handheld role-playing video games for Nintendo''s Game Boy Color. Of the three games, only Sun was released in North America in December 2000 by Atlus, while their original Japan releases were by Hudson Soft. The games focus on a boy, named Cody by default, and his adventures on his island with his robotic friends. They mostly resemble the Pokémon series of video games, but also bear similarities to the Super Nintendo Entertainment System game Robotrek, published by Enix.', 'https://media.retroachievements.org/Images/033790.png', 'https://media.retroachievements.org/Images/023929.png', 'https://media.retroachievements.org/Images/023920.png', 'https://media.retroachievements.org/Images/023921.png', 4.1),
  (150, 22353, '~Homebrew~ Hime''s Quest', 'Game Boy Color', 6, 192, 192, 192, 35, 0, 'Action-Adventure', 'Poppy Works', 'Crunchyroll | Limited Run Games', '2023-01-25', 'The Game Boy portable system has a library of games, which were released in plastic ROM cartridges. The Game Boy first launched in Japan on April 21, 1989, with Super Mario Land, Alleyway, Baseball, and Yakuman. For the North American launches, Tetris and Tennis were also featured, while Yakuman was never released outside of Japan. The last games to be published for the system were the Japan-only titles Shikakui Atama o Maruku Suru: Kanji no Tatsujin and Shikakui Atama o Maruku Suru: Keisan no Tatsujin, both released on March 30, 2001.', 'https://media.retroachievements.org/Images/068576.png', 'https://media.retroachievements.org/Images/068583.png', 'https://media.retroachievements.org/Images/068571.png', 'https://media.retroachievements.org/Images/068572.png', 4.1),
  (151, 4058, 'Looney Tunes: Twouble!', 'Game Boy Color', 6, 192, 192, 192, 26, 0, '2.5D Platforming, Puzzle', 'Bit Managers', 'Infogrames', '1998-12-01', 'Sylvester & Tweety: Breakfast on the Run, known as Looney Tunes: Twouble! in North America, is a 2D and isometric, pseudo-3D platform video game developed by Bit Managers and published by Infogrames for the Game Boy Color in 1998. It features the Looney Tunes characters Sylvester and Tweety. Other Looney Tunes include Bugs Bunny, Daffy Duck, Granny, Hector the Bulldog, Taz, Pepé Le Pew and Marvin the Martian.', 'https://media.retroachievements.org/Images/061702.png', 'https://media.retroachievements.org/Images/059604.png', 'https://media.retroachievements.org/Images/059603.png', 'https://media.retroachievements.org/Images/059602.png', 4.1),
  (152, 30882, '~Homebrew~ Little Dungeon Renovator', 'Game Boy Color', 6, 190, 190, 190, 10, 0, NULL, 'MashinN', 'MashinN', '2023-09-14', 'Tegel Manor is a 1977 fantasy role-playing game adventure published by Judges Guild.', 'https://media.retroachievements.org/Images/111692.png', 'https://media.retroachievements.org/Images/103841.png', 'https://media.retroachievements.org/Images/111677.png', 'https://media.retroachievements.org/Images/111678.png', 4.1),
  (153, 17975, 'Das Geheimnis der Happy Hippo-Insel', 'Game Boy Color', 6, 190, 190, 190, 12, 0, '2D Platforming', 'KRITZELKRATZ 3000', 'Infogrames', '2001-05-17', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/048559.png', 'https://media.retroachievements.org/Images/048557.png', 'https://media.retroachievements.org/Images/048556.png', 'https://media.retroachievements.org/Images/048560.png', 4.1),
  (154, 7450, 'Return of the Ninja', 'Game Boy Color', 6, 189, 189, 189, 15, 0, '2D Platforming', 'Natsume', 'Natsume', '2001-03-30', 'Return of the Ninja is a platform game with stealth elements developed by Act Japan and published by Natsume Inc. for the Game Boy Color in 2001 as a spiritual successor to 1990''s Shadow of the Ninja.', 'https://media.retroachievements.org/Images/089679.png', 'https://media.retroachievements.org/Images/033010.png', 'https://media.retroachievements.org/Images/089804.png', 'https://media.retroachievements.org/Images/033011.png', 4.1),
  (155, 22849, '~Hack~ The Legend of Zelda: Archipelago', 'Game Boy Color', 6, 184, 184, 184, 14, 0, NULL, 'Nobody', 'Hack - The Legend of Zelda: Oracle of Ages', '2020-06-05', 'The Legend of Zelda is a video game franchise created by video game designers Shigeru Miyamoto and Takashi Tezuka and mainly developed and published by Nintendo. The universe of the Legend of Zelda series consists of various lands, the most predominant being Hyrule. The franchise is set within a fantasy world reminiscent of medieval Europe which consists of several recurring locations, races and creatures. The world was also partially inspired by Miyamoto and designer Hidemaro Fujibayashi''s home town, Kyoto. The most prominent race in the series are the Hylians, a humanoid race with elfin features identifiable by their long, pointed ears. The series'' lore contains a creation myth, several fictional alphabets, the most prominent being Hylian, and a fictional almost-universal currency, the rupee. The games involve the protagonists Link and Princess Zelda battling monsters to save the various lands they are in, and defeat a villain, which is often the series'' main antagonist, Ganon. Link is usually the main player character in these settings, but players primarily play as Zelda in 2024''s Echoes of Wisdom. Nintendo developed the series'' lore into a timeline that spans thousands of years across its history.', 'https://media.retroachievements.org/Images/069603.png', 'https://media.retroachievements.org/Images/069618.png', 'https://media.retroachievements.org/Images/069616.png', 'https://media.retroachievements.org/Images/069617.png', 4.1),
  (156, 9269, '~Hack~ Pokémon Kalos Crystal', 'Game Boy Color', 6, 181, 181, 181, 81, 0, 'Turn-Based RPG', 'Azure Keys', 'Hack - Pokemon Crystal Version', '2018-01-01', 'Pokémon is a series of role-playing video games developed by Game Freak and published by Nintendo and The Pokémon Company. Over the years, a number of spin-off games based on the series have also been developed by multiple companies. While the main series consists of RPGs, spin-off games encompass other genres, such as action role-playing, puzzle, fighting, and digital pet games. Most Pokémon video games have been developed exclusively for Nintendo handheld and home consoles, dating from the Game Boy to the Nintendo Switch 2.', 'https://media.retroachievements.org/Images/091204.png', 'https://media.retroachievements.org/Images/059364.png', 'https://media.retroachievements.org/Images/058913.png', 'https://media.retroachievements.org/Images/058914.png', 4.1),
  (157, 6009, 'Barbie: Fashion Pack Games', 'Game Boy Color', 6, 181, 181, 181, 8, 0, 'Minigames', 'Hyperspace Cowgirls', 'Mattel', '2000-08-15', 'Barbie, a fashion doll manufactured by American toy and entertainment company Mattel, has starred in numerous video games on PC, various console systems, IOS, and Android. Some games are adaptations of Barbie films or TV series, while others feature original storylines and concepts.', 'https://media.retroachievements.org/Images/118235.png', 'https://media.retroachievements.org/Images/118233.png', 'https://media.retroachievements.org/Images/118232.png', 'https://media.retroachievements.org/Images/118231.png', 4.1),
  (158, 2499, 'Noddy and the Birthday Party', 'Game Boy Color', 6, 180, 180, 180, 20, 0, '2D Platforming, Educational', 'Tiertex Design Studios', 'BBC Multimedia', '2000-12-30', 'Noddy and the Birthday Party is a children''s video game released only in Europe for the Game Boy Color in 2000. It was developed by Tiertex Design Studios and published by BBC Multimedia. The game is based on the character Noddy by Enid Blyton, as well as the fictional universe in which he resides. The focus of the plot and gameplay is the preparation of the character Big-Ears'' upcoming birthday party. The game received mixed to negative reviews from critics.', 'https://media.retroachievements.org/Images/075532.png', 'https://media.retroachievements.org/Images/072481.png', 'https://media.retroachievements.org/Images/055397.png', 'https://media.retroachievements.org/Images/055393.png', 4.1),
  (159, 13053, 'Monopoly', 'Game Boy Color', 6, 179, 179, 179, 35, 0, 'Board Game', 'Sculptured Software | Iguana West', 'Majesco Entertainment', '1998-12-11', 'A monopoly is a market in which one person or company is the only supplier of a particular good or service. A monopoly is characterized by a lack of economic competition to produce a particular thing, a lack of viable substitute goods, and the possibility of a high monopoly price well above the seller''s marginal cost that leads to a high monopoly profit. The verb monopolise or monopolize refers to the process by which a company gains the ability to raise prices or exclude competitors. In economics, a monopoly is a single seller. In law, a monopoly is a business entity that has significant market power, that is, the power to charge overly high prices, which is associated with unfair price raises. Although monopolies may be big businesses, size is not a characteristic of a monopoly. A small business may still have the power to raise prices in a small industry.', 'https://media.retroachievements.org/Images/060627.png', 'https://media.retroachievements.org/Images/060037.png', 'https://media.retroachievements.org/Images/060035.png', 'https://media.retroachievements.org/Images/060038.png', 4.1),
  (160, 31955, '~Homebrew~ ~Demo~ The New Adventures of Sonic the Hedgehog', 'Game Boy Color', 6, 177, 177, 177, 16, 0, '2D Platforming', 'Oasys', 'Oasys', '2024-08-13', 'Disney''s Aladdin is a 1993 side-scrolling platformer video game developed by Virgin Games and published by Sega for the Sega Genesis. The game is based on the 1992 Walt Disney Animation Studios film of the same name, and features the titular Aladdin navigating settings and scenarios from the film.', 'https://media.retroachievements.org/Images/110539.png', 'https://media.retroachievements.org/Images/110478.png', 'https://media.retroachievements.org/Images/110476.png', 'https://media.retroachievements.org/Images/110477.png', 4.1),
  (161, 4940, 'Xtreme Sports', 'Game Boy Color', 6, 176, 176, 176, 36, 0, 'Extreme Sports', 'WayForward', 'Infogrames', '2000-06-28', 'X-Treme Sports was a Canadian English language category 2 television channel owned by Canwest Media Inc., a division of Canwest Global Communications. X-Treme Sports aired a variety of programming primarily related to extreme sports.', 'https://media.retroachievements.org/Images/060938.png', 'https://media.retroachievements.org/Images/095587.png', 'https://media.retroachievements.org/Images/095500.png', 'https://media.retroachievements.org/Images/095499.png', 4.1),
  (162, 8402, 'Toy Story 2', 'Game Boy Color', 6, 175, 175, 175, 46, 0, '2D Platforming', 'Tiertex Design Studios', 'THQ', '1999-11-01', 'Toy Story 2 is a 1999 American animated adventure comedy film produced by Pixar Animation Studios for Walt Disney Pictures. It is the second installment in Pixar''s Toy Story franchise and the sequel to the original 1995 film. The film was directed by John Lasseter from a screenplay by Andrew Stanton, Rita Hsiao, Doug Chamberlin, and Chris Webb. Tom Hanks, Tim Allen, Don Rickles, Jim Varney, Wallace Shawn, John Ratzenberger, Annie Potts, R. Lee Ermey, John Morris, Laurie Metcalf and Jeff Pidgeon reprise their roles from the first Toy Story film, with newcomers Joan Cusack, Kelsey Grammer, Wayne Knight, Estelle Harris, and Jodi Benson joining the cast. In the film, Woody is stolen by a greedy toy collector, prompting Buzz Lightyear and his friends to save him, but Woody is then tempted by the idea of immortality in a museum.', 'https://media.retroachievements.org/Images/054343.png', 'https://media.retroachievements.org/Images/050870.png', 'https://media.retroachievements.org/Images/050855.png', 'https://media.retroachievements.org/Images/050856.png', 4.1),
  (163, 20371, '~Homebrew~ Super Jacked Up Tomato Face Johnson', 'Game Boy Color', 6, 174, 174, 174, 14, 0, '2D Platforming', 'Gumpy Function', 'Gumpy Function', '2022-05-29', 'The Mummy is a 1999 American action-adventure film written and directed by Stephen Sommers, starring Brendan Fraser, Rachel Weisz, John Hannah, and Arnold Vosloo as the reanimated mummy. It is a loose remake of the 1932 film. The Mummy follows adventurer and treasure hunter Rick O''Connell as he travels to Hamunaptra, the City of the Dead, with librarian Evelyn Carnahan and her older brother Jonathan, where they accidentally awaken Imhotep, a cursed high priest with supernatural powers.', 'https://media.retroachievements.org/Images/061190.png', 'https://media.retroachievements.org/Images/061235.png', 'https://media.retroachievements.org/Images/061191.png', 'https://media.retroachievements.org/Images/061192.png', 4.1),
  (164, 14123, 'Yu-Gi-Oh! Duel Monsters II: Dark Duel Stories', 'Game Boy Color', 6, 174, 174, 174, 68, 0, 'Collectible Card Game', 'Konami', 'Konami', '1999-07-08', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/092435.png', 'https://media.retroachievements.org/Images/024082.png', 'https://media.retroachievements.org/Images/024080.png', 'https://media.retroachievements.org/Images/024081.png', 4.1),
  (165, 3671, 'Pooh and Tigger''s Hunny Safari', 'Game Boy Color', 6, 172, 172, 172, 32, 0, '2D Platforming', 'Digital Eclipse', 'Electronic Arts, Ubisoft', '2001-12-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/067800.png', 'https://media.retroachievements.org/Images/067803.png', 'https://media.retroachievements.org/Images/067801.png', 'https://media.retroachievements.org/Images/067802.png', 4.1),
  (166, 4526, 'Beatmania GB: GotchaMix 2', 'Game Boy Color', 6, 171, 171, 171, 133, 0, 'Rhythm', 'Konami', 'Konami', '2000-09-28', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/122217.png', 'https://media.retroachievements.org/Images/060849.png', 'https://media.retroachievements.org/Images/060847.png', 'https://media.retroachievements.org/Images/060848.png', 4.1),
  (167, 6556, 'Woody Woodpecker: Escape from Buzz Buzzard Park', 'Game Boy Color', 6, 171, 171, 171, 40, 0, '2D Platforming', 'Planet Interactive', 'Cryo Interactive, DreamCatcher Interactive', '2001-06-07', 'Woody Woodpecker: Escape from Buzz Buzzard Park is a set of two video games based on the animated series The New Woody Woodpecker Show. One is for PlayStation 2 and Windows, and the other is for the Game Boy Color.', 'https://media.retroachievements.org/Images/060180.png', 'https://media.retroachievements.org/Images/118857.png', 'https://media.retroachievements.org/Images/124114.png', 'https://media.retroachievements.org/Images/124115.png', 4.1),
  (168, 6251, '~Hack~ The Legend of Zelda: Hard Awakening DX', 'Game Boy Color', 6, 168, 168, 168, 15, 0, 'Action-Adventure', 'Jeville', 'Hack - The Legend of Zelda: Link''s Awakening', '2013-04-05', 'The Legend of Zelda: Link''s Awakening is a 1993 action-adventure game developed and published by Nintendo for the Game Boy. It is the first installment in The Legend of Zelda series to be released on a handheld game console. Link''s Awakening is one of the few Zelda games not to take place in the land of Hyrule, and it does not feature Princess Zelda or the Triforce relic. Instead, the protagonist Link begins the game stranded on Koholint Island, a place guarded by a whale-like deity called the Wind Fish. Assuming the role of Link, the player fights monsters and solves puzzles while searching for eight musical instruments that will awaken the sleeping Wind Fish and allow him to escape from the island.', 'https://media.retroachievements.org/Images/025126.png', 'https://media.retroachievements.org/Images/042279.png', 'https://media.retroachievements.org/Images/005509.png', 'https://media.retroachievements.org/Images/005510.png', 4.1),
  (169, 11165, 'Bugs Bunny and Lola Bunny: Operation Carrot Patch', 'Game Boy Color', 6, 165, 165, 165, 18, 0, '2D Platforming', 'Velez & Dubail Dev. Team', 'Infogrames', '1999-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/015109.png', 'https://media.retroachievements.org/Images/015108.png', 'https://media.retroachievements.org/Images/015106.png', 'https://media.retroachievements.org/Images/015107.png', 4.1),
  (170, 8539, '~Unlicensed~ Donkey Kong 5: The Journey of Over Time and Space', 'Game Boy Color', 6, 162, 162, 162, 42, 0, NULL, 'Sintax', 'BBD', '2001-01-01', 'Disney''s Aladdin is a 1993 side-scrolling platformer video game developed by Virgin Games and published by Sega for the Sega Genesis. The game is based on the 1992 Walt Disney Animation Studios film of the same name, and features the titular Aladdin navigating settings and scenarios from the film.', 'https://media.retroachievements.org/Images/047608.png', 'https://media.retroachievements.org/Images/008599.png', 'https://media.retroachievements.org/Images/008600.png', 'https://media.retroachievements.org/Images/042561.png', 4.1),
  (171, 30128, '~Homebrew~ Enceladus', 'Game Boy Color', 6, 161, 161, 161, 7, 0, '2D Platforming', 'Marco Windrich, Dominik Zimmer', 'Marco Windrich, Dominik Zimmer', '2023-09-12', 'Enceladus is the sixth-largest moon of Saturn and the 18th largest in the Solar System. It is about 500 kilometres in diameter, about a tenth of that of Saturn''s largest moon, Titan. It is covered by clean, freshly deposited snow hundreds of meters thick, making it one of the most reflective bodies of the Solar System. Consequently, its surface temperature at noon reaches only −198 °C, far colder than a light-absorbing body would be. Despite its small size, Enceladus has a wide variety of surface features, ranging from old, heavily cratered regions to young, tectonically deformed terrain.', 'https://media.retroachievements.org/Images/112090.png', 'https://media.retroachievements.org/Images/099114.png', 'https://media.retroachievements.org/Images/099111.png', 'https://media.retroachievements.org/Images/099112.png', 4.1),
  (172, 32799, 'Deer Hunter', 'Game Boy Color', 6, 161, 161, 161, 13, 0, 'Sports - Hunting', 'Morning Star Multimedia', 'Vatical Entertainment', '1999-12-22', 'Deer Hunter is a series of hunting simulation video games. Originally available for Windows platform published by WizardWorks, it has since been published on MacOS, Game Boy Color, PlayStation 2, and mobile phones. The first Deer Hunter game was an early success in the casual game market.', 'https://media.retroachievements.org/Images/112401.png', 'https://media.retroachievements.org/Images/112400.png', 'https://media.retroachievements.org/Images/106262.png', 'https://media.retroachievements.org/Images/124984.png', 4.1),
  (173, 29047, '~Homebrew~ Hollow Knight Silksong', 'Game Boy Color', 6, 160, 160, 160, 16, 0, 'Metroidvania', 'Elvies', 'Elvies', '2021-07-28', 'Hollow Knight: Silksong is a 2025 Metroidvania game developed and published by Australian independent developer Team Cherry. The sequel to Hollow Knight (2017), it was released on 4 September 2025 for Linux, macOS, Nintendo Switch, Nintendo Switch 2, PlayStation 4, PlayStation 5, Windows, Xbox One, and Xbox Series X/S.', 'https://media.retroachievements.org/Images/111197.png', 'https://media.retroachievements.org/Images/119810.png', 'https://media.retroachievements.org/Images/093103.png', 'https://media.retroachievements.org/Images/093102.png', 4.1),
  (174, 22650, '~Homebrew~ Repugnant Bounty', 'Game Boy Color', 6, 160, 160, 160, 30, 0, 'Metroidvania', 'Starlab', 'Starlab', '2022-12-23', 'Jonah Woodson Hex is a fictional antihero appearing in American comic books published by DC Comics. The character was created by writer John Albano and artist Tony DeZuniga. Hex is a surly and cynical bounty hunter whose face is scarred on the right side. Despite his poor reputation and personality, Hex is bound by a personal code of honor to protect and avenge the innocent.', 'https://media.retroachievements.org/Images/070057.png', 'https://media.retroachievements.org/Images/070058.png', 'https://media.retroachievements.org/Images/069557.png', 'https://media.retroachievements.org/Images/070024.png', 4.1),
  (175, 18811, '~Homebrew~ Go Catch ''Em', 'Game Boy Color', 6, 158, 158, 158, 29, 0, 'Action', 'Health Potion Studios', 'Health Potion Studios', '2022-02-25', 'Xena: Warrior Princess is a hack and slash video game developed by Universal Studios Digital Arts and co-published by Electronic Arts and Universal Interactive Studios for the PlayStation in 1999. A Game Boy Color version was developed and published by Titus Interactive in 2001. Each version is based on the television series of the same name, which aired from 1995 to 2001.', 'https://media.retroachievements.org/Images/113263.png', 'https://media.retroachievements.org/Images/113257.png', 'https://media.retroachievements.org/Images/113259.png', 'https://media.retroachievements.org/Images/113258.png', 4.1),
  (176, 33660, '~Homebrew~ Oshinui Tune', 'Game Boy Color', 6, 157, 157, 157, 14, 0, 'Shoot ''em Up', 'megamittz', 'megamittz', '2025-05-07', NULL, 'https://media.retroachievements.org/Images/112810.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/112779.png', 'https://media.retroachievements.org/Images/112778.png', 4.1),
  (177, 8461, 'Spider-Man 2: The Sinister Six', 'Game Boy Color', 6, 153, 153, 153, 19, 0, 'Action, 2D Platforming', 'Torus Games', 'Activision', '2001-05-30', 'Spider-Man 2: The Sinister Six is a 2001 platform video game based on the Marvel Comics character Spider-Man. It was developed by Torus Games and published by Activision for the Game Boy Color. It was released on May 18, 2001, and is a sequel to Spider-Man (2000).', 'https://media.retroachievements.org/Images/067970.png', 'https://media.retroachievements.org/Images/015539.png', 'https://media.retroachievements.org/Images/067540.png', 'https://media.retroachievements.org/Images/015538.png', 4.1),
  (178, 30985, 'Sylvanian Melodies: Mori no Nakama to Odori Masho!', 'Game Boy Color', 6, 147, 147, 147, 31, 0, NULL, NULL, 'Epoch', '2000-03-17', 'Sylvanian Families  is a line of collectible anthropomorphic animal figurines made of flocked plastic. They were created by the Japanese gaming company Epoch in 1985 and distributed worldwide by a number of companies.', 'https://media.retroachievements.org/Images/102834.png', 'https://media.retroachievements.org/Images/102779.png', 'https://media.retroachievements.org/Images/102786.png', 'https://media.retroachievements.org/Images/102787.png', 4.1),
  (179, 6104, 'Towers: Lord Baniff''s Deceit', 'Game Boy Color', 6, 147, 147, 147, 41, 0, 'CRPG, Dungeon Crawl', 'JV Enterprises', 'Telegames, Vatical Entertainment', '1999-01-01', 'Towers: Lord Baniff''s Deceit is a first-person role-playing video game originally developed and published by JV Enterprises for the Atari ST in 1993. It is the first entry in the Towers series. In the game, players assume the role of adventurers tasked with finding Lord Baniff in his Tower, who has not been heard from by the people of Lamini. The title was later ported to both MS-DOS and Game Boy Color, each featuring various differences compared to the original release. It was met with mixed reception from critics across all platforms. A sequel, Towers II: Plight of the Stargazer, was released in 1995 for the Atari Falcon.', 'https://media.retroachievements.org/Images/057679.png', 'https://media.retroachievements.org/Images/057680.png', 'https://media.retroachievements.org/Images/057677.png', 'https://media.retroachievements.org/Images/057678.png', 4.1),
  (180, 7210, 'Star Wars - Episode I: Racer', 'Game Boy Color', 6, 144, 144, 144, 27, 0, 'Arcade Racing', 'LucasArts | Lucasfilm, Pax Softnica', 'Nintendo', '1999-12-01', 'Star Wars Episode I: Racer is a 1999 racing video game developed and published by LucasArts. It is based on the podracing sequence in the film Star Wars: Episode I – The Phantom Menace. The game features all of the racers and race course on Tatooine from The Phantom Menace. It adds several new courses, on Tatooine and various planets. The game has several single player modes, including a tournament mode. The format of multiplayer mode varies by platform. Jake Lloyd and Lewis MacLeod, who portrayed Anakin Skywalker and Sebulba in The Phantom Menace, reprise their film roles in the game.', 'https://media.retroachievements.org/Images/069456.png', 'https://media.retroachievements.org/Images/091362.png', 'https://media.retroachievements.org/Images/105149.png', 'https://media.retroachievements.org/Images/105150.png', 4.1),
  (181, 8337, 'Montezuma''s Return', 'Game Boy Color', 6, 139, 139, 139, 21, 0, '2D Platformer', 'Tarantula Studios', 'Take-Two Interactive', '1998-12-01', 'Montezuma''s Return! is a 1997 action/adventure video game and the sequel to the original Parker Brothers game Montezuma''s Revenge. While the original game was a 2D platform game, the sequel was a 3D first-person puzzle platformer. According to Steve Bergenholtz, the Utopia Technologies spokesperson, the musical score was written by a TV and film veteran. A port for Nintendo 64 was in the works but was cancelled.', 'https://media.retroachievements.org/Images/062143.png', 'https://media.retroachievements.org/Images/059745.png', 'https://media.retroachievements.org/Images/059747.png', 'https://media.retroachievements.org/Images/059748.png', 4.1),
  (182, 29775, '~Homebrew~ Wishing Sarah', 'Game Boy Color', 6, 137, 137, 137, 21, 0, 'Adventure', 'Asteristic Game Studio', 'Asteristic Game Studio', '2020-05-12', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/096775.png', 'https://media.retroachievements.org/Images/096774.png', 'https://media.retroachievements.org/Images/096595.png', 'https://media.retroachievements.org/Images/096596.png', 4.1),
  (183, 28383, '~Homebrew~ Remote Control Shuriken', 'Game Boy Color', 6, 136, 136, 136, 6, 0, NULL, 'Health Potion Studios', 'itch.io', '2021-10-16', 'Ninja Crusaders is a side-scrolling action game released by Sammy Corporation for the Nintendo Entertainment System in 1990. The player takes control of one of two ninjas who are tasked at thwarting an alien invasion. The game has been compared to Tecmo''s Ninja Gaiden series.', 'https://media.retroachievements.org/Images/089036.png', 'https://media.retroachievements.org/Images/089083.png', 'https://media.retroachievements.org/Images/089034.png', 'https://media.retroachievements.org/Images/089035.png', 4),
  (184, 14039, 'Perfect Dark', 'Game Boy Color', 6, 134, 134, 134, 34, 0, 'Stealth, Third-Person Shooter', 'Rare', 'Rareware Limited', '2000-08-28', 'Perfect Dark is a 2000 first-person shooter game developed and published by Rare for the Nintendo 64. The first game of the Perfect Dark series, it follows Joanna Dark, an agent of the Carrington Institute research centre, as she attempts to stop an extraterrestrial conspiracy by rival corporation dataDyne. The game features a campaign mode where the player must complete a series of levels to progress through the story, as well as a range of multiplayer options, including a co-operative mode and traditional deathmatch settings with computer-controlled bots.', 'https://media.retroachievements.org/Images/115215.png', 'https://media.retroachievements.org/Images/089666.png', 'https://media.retroachievements.org/Images/091489.png', 'https://media.retroachievements.org/Images/093995.png', 4),
  (185, 15925, 'Loppi Puzzle Magazine: Kangaeru Puzzle Soukangou', 'Game Boy Color', 6, 133, 133, 133, 10, 0, NULL, 'Success, Game Studio', 'Success', '2001-08-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/052400.png', 'https://media.retroachievements.org/Images/052241.png', 'https://media.retroachievements.org/Images/052401.png', 'https://media.retroachievements.org/Images/052402.png', 4),
  (186, 6791, 'Gex 3: Deep Pocket Gecko', 'Game Boy Color', 6, 131, 131, 131, 24, 0, '2D Platforming', 'David A. Palmer Productions', 'Eidos Interactive', '1999-12-01', 'Gex 3: Deep Pocket Gecko is a 1999 platformer video game developed by David A. Palmer IMS Productions and published by Eidos Interactive for the Game Boy Color. It is part of the Gex of games, where the player controls a gecko named Gex through a series of television and film-themed 2D side-scrolling levels where he collects various items to progress through the game. In the game, Gex is trying to reach Agent Xtra who has been kidnapped and must reach his long-standing enemy Rez-Raker to do so.', 'https://media.retroachievements.org/Images/045851.png', 'https://media.retroachievements.org/Images/005982.png', 'https://media.retroachievements.org/Images/005983.png', 'https://media.retroachievements.org/Images/005994.png', 4),
  (187, 7666, 'Hot Wheels: Stunt Track Driver', 'Game Boy Color', 6, 131, 131, 131, 24, 0, 'Arcade Racing', 'Lucky Chicken Games', 'Mattel', '2000-01-01', 'Hot Wheels Stunt Track Driver is a racing video game developed by Semi Logic Entertainments and published by Mattel Media for Microsoft Windows. It is based on the Hot Wheels toy franchise, and was released on October 15, 1998. A Game Boy Color version, developed by Lucky Chicken Games, was released in 2000.', 'https://media.retroachievements.org/Images/025592.png', 'https://media.retroachievements.org/Images/025593.png', 'https://media.retroachievements.org/Images/025590.png', 'https://media.retroachievements.org/Images/025591.png', 4),
  (188, 3647, 'MIB: Men in Black - The Series', 'Game Boy Color', 6, 130, 130, 130, 15, 0, '2D Platforming', 'Tiertex Design Studios', 'Crave Entertainment', '1999-03-01', 'Men in Black: The Series is an action platform video game developed by Tiertex Design Studios and published by Crave Entertainment for the Game Boy Color (GBC) on December 14, 1998. The game is based on the animated television series of the same name, and was followed by a sequel titled Men in Black 2: The Series, released for the Game Boy Color in 2000.', 'https://media.retroachievements.org/Images/045912.png', 'https://media.retroachievements.org/Images/023360.png', 'https://media.retroachievements.org/Images/023361.png', 'https://media.retroachievements.org/Images/023363.png', 4),
  (189, 4302, 'The Fish Files', 'Game Boy Color', 6, 128, 128, 128, 33, 0, 'Point-and-Click Adventure', '7th Sense', 'Microids', '2001-11-29', 'The Fish Files is a 2001 adventure game developed by the Italian team 7th Sense and published by MC2-Microïds on the Game Boy Color.', 'https://media.retroachievements.org/Images/022751.png', 'https://media.retroachievements.org/Images/022752.png', 'https://media.retroachievements.org/Images/026384.png', 'https://media.retroachievements.org/Images/022750.png', 4),
  (190, 12864, 'Meitantei Conan: Kigantou Hihou Densetsu', 'Game Boy Color', 6, 127, 127, 127, 11, 0, NULL, NULL, NULL, '2000-05-31', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/073581.png', 'https://media.retroachievements.org/Images/017553.png', 'https://media.retroachievements.org/Images/017554.png', 'https://media.retroachievements.org/Images/019720.png', 4),
  (191, 28190, '~Homebrew~ The Mandalorian - Chapter 3: The Sin', 'Game Boy Color', 6, 122, 122, 122, 10, 0, 'Action', 'Eric C. Wilder', 'itch.io', '2021-01-01', '"Chapter 3: The Sin" is the third episode of the first season of the American streaming television series The Mandalorian. It was written by the series'' showrunner Jon Favreau and directed by Deborah Chow. The episode takes place in the Star Wars universe five years after the events of Return of the Jedi (1983). In the episode, the Mandalorian successfully delivers the Child to the Client. However, the Mandalorian feeling guilty of handing over the Child decides to rescue the latter. This causes the two to become fugitives from the Guild, forcing them to leave Nevarro and go into hiding.', 'https://media.retroachievements.org/Images/093505.png', 'https://media.retroachievements.org/Images/093499.png', 'https://media.retroachievements.org/Images/093503.png', 'https://media.retroachievements.org/Images/093504.png', 4),
  (192, 711, 'LEGO Stunt Rally', 'Game Boy Color', 6, 122, 122, 122, 20, 0, 'Arcade Racing', 'Graphic State', 'LEGO Interactive | LEGO Media', '2000-12-29', 'Lego Stunt Rally is a 2000 racing game themed around the Lego line of construction toys. The Windows version was developed by Intelligent Games and published by Lego Media.', 'https://media.retroachievements.org/Images/055741.png', 'https://media.retroachievements.org/Images/018080.png', 'https://media.retroachievements.org/Images/101085.png', 'https://media.retroachievements.org/Images/101086.png', 4),
  (193, 26179, '~Homebrew~ Octopus Stressus', 'Game Boy Color', 6, 121, 121, 121, 7, 0, NULL, 'allalonegamez', 'allalonegamez', '2023-04-23', NULL, 'https://media.retroachievements.org/Images/084169.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/084167.png', 'https://media.retroachievements.org/Images/084168.png', 4),
  (194, 17359, 'Atlantis: The Lost Empire', 'Game Boy Color', 6, 118, 118, 118, 27, 0, '2D Platforming', 'Eurocom', 'THQ', '2001-07-30', 'Atlantis: The Lost Empire is a 2001 American animated science fiction adventure film directed by Gary Trousdale and Kirk Wise, produced by Don Hahn, and written by Tab Murphy. Produced by Walt Disney Feature Animation, it stars Michael J. Fox, James Garner, Cree Summer, Don Novello, Phil Morris, Claudia Christian, Jacqueline Obradors, Florence Stanley, David Ogden Stiers, John Mahoney, Jim Varney, Corey Burton and Leonard Nimoy. Set in 1914, it follows young linguist Milo Thatch, who gains possession of a sacred book, which he believes will guide him and a crew of mercenaries to the lost city of Atlantis.', 'https://media.retroachievements.org/Images/043864.png', 'https://media.retroachievements.org/Images/041053.png', 'https://media.retroachievements.org/Images/041028.png', 'https://media.retroachievements.org/Images/041029.png', 4),
  (195, 4646, 'Mickey''s Speedway USA', 'Game Boy Color', 6, 118, 118, 118, 202, 0, 'Kart Racing', 'Rare', 'Nintendo', '2001-03-23', 'Mickey''s Speedway USA is a kart racing game developed by Rare and published by Nintendo for the Nintendo 64 and Game Boy Color. It is Rare and Nintendo''s second collaboration with Disney Interactive following Mickey''s Racing Adventure (1999), and features characters from the Mickey Mouse universe racing across the United States. The Nintendo 64 game released in November 2000 to mixed reception, while the Game Boy Color version followed in March 2001.', 'https://media.retroachievements.org/Images/112013.png', 'https://media.retroachievements.org/Images/022174.png', 'https://media.retroachievements.org/Images/022175.png', 'https://media.retroachievements.org/Images/022176.png', 4),
  (196, 5042, 'Monster Rancher Explorer', 'Game Boy Color', 6, 115, 115, 115, 31, 0, NULL, 'Tecmo', 'Koei | Tecmo', '2000-09-29', 'Monster Rancher Explorer is a 2000 puzzle game developed by Graphic Research and published by Tecmo for the Game Boy Color. It features the same gameplay elements as Solomon''s Key but includes Monster Rancher characters.', 'https://media.retroachievements.org/Images/064809.png', 'https://media.retroachievements.org/Images/002987.png', 'https://media.retroachievements.org/Images/040698.png', 'https://media.retroachievements.org/Images/002984.png', 4),
  (197, 4972, 'Revelations: The Demon Slayer', 'Game Boy Color', 6, 115, 115, 115, 31, 0, 'Turn-Based RPG', 'Access, Multimedia Intelligence Transfer', 'Atlus', '1999-03-19', 'Revelations : The Demon Slayer  is a role-playing video game developed by Access and Multimedia Intelligence Transfer, and published by Atlus, Index and Sega, initially released on Game Boy on December 25, 1992 in Japan under the name ‘''Megami Tensei Gaiden: Last Bible’''. It is the first color RPG for Game Boy Color released in North America.', 'https://media.retroachievements.org/Images/091552.png', 'https://media.retroachievements.org/Images/002677.png', 'https://media.retroachievements.org/Images/002678.png', 'https://media.retroachievements.org/Images/008334.png', 4),
  (198, 4301, 'Fix and Foxi - Episode 1: Lupo', 'Game Boy Color', 6, 110, 110, 110, 12, 0, '2D Platforming', 'Similis Software', 'Ravensburger', '2000-01-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/039490.png', 'https://media.retroachievements.org/Images/024035.png', 'https://media.retroachievements.org/Images/024033.png', 'https://media.retroachievements.org/Images/024034.png', 4),
  (199, 9169, 'Moomin''s Tale', 'Game Boy Color', 6, 108, 108, 108, 16, 0, NULL, 'Pixel', 'Sunsoft', '2000-09-30', 'The Moomins are the central characters in a series of novels, short stories, picture books, and a comic strip by the Finnish writer and illustrator Tove Jansson, originally published in Swedish by the Finnish publisher Schildts. They are a family of white, round fairy-tale characters with large snouts that make them resemble the hippopotamus. However, despite this resemblance, the Moomin family are trolls who live in a house in Moominvalley.', 'https://media.retroachievements.org/Images/069454.png', 'https://media.retroachievements.org/Images/101352.png', 'https://media.retroachievements.org/Images/120618.png', 'https://media.retroachievements.org/Images/120619.png', 4),
  (200, 15926, 'Loppi Puzzle Magazine: Kangaeru Puzzle Dai-2-gou', 'Game Boy Color', 6, 106, 106, 106, 10, 0, NULL, 'Success', 'Success', '2001-10-01', 'This list of Game Boy Color games includes 915 licensed releases from the Game Boy Color''s launch in 1998 to the final release in 2003. The last official release for the system was Doraemon no Study Boy: Kanji Yomikaki Master, which was released in Japan on July 18, 2003. However, multiple unlicensed games have been released since then. Additionally, there were several games which were developed and officially licensed, but were cancelled before release.', 'https://media.retroachievements.org/Images/052239.png', 'https://media.retroachievements.org/Images/052240.png', 'https://media.retroachievements.org/Images/052404.png', 'https://media.retroachievements.org/Images/052403.png', 4);
